def loadMasterData(type) {
  		if (not call isUSM()) {
	  		if (type eq 'no_delivery') {
	  			if (not VarDefined('CHANGED_NO_DELIVERY')) {
        			global CHANGED_NO_DELIVERY =  TableRows(Load(ConcatPath(customSystemfileDir, 'pcm_changeddata.xml'), 'table', 'row'), 'Lieferstatus', 'nicht_mehr_lieferbar', false);
        		};
        	} else
        	if (type eq 'base') {
	        	global BASE = Load(ConcatPath(customSystemfileDir, 'pcm_masterdata.xml'), 'table', 'row');
        	} else
        	if (type eq 'changed') {
        		global CHANGED = TableRows(Load(ConcatPath(customSystemfileDir, 'pcm_changeddata.xml'), 'table', 'row'), 'Lieferstatus', 'auslauf', false);
	        };

	  	} else {
	  		if (type eq 'no_delivery') {
	  			if (not VarDefined('CHANGED_NO_DELIVERY')) {
        			global CHANGED_NO_DELIVERY =  TableRows(AsList(Load('crdf://pcm_changed','table','row')), 'Lieferstatus', 'nicht_mehr_lieferbar', false);
        		};
        	} else
        	if (type eq 'base') {
	        	global BASE = AsList(Load('crdf://pcm_masterdata','table','row'));
        	} else
        	if (type eq 'changed') {
        		global CHANGED = TableRows(AsList(Load('crdf://pcm_changed','table','row')), 'Lieferstatus', 'auslauf', false);
	        };

	  	};
  	};

def getRootParentOfType(part, structure, type) {
  		my parent = null;
		my p = part;
  		my finished = false;
  		while (not finished) {

  			p = ParentOfType(p, structure, type);
  			if (p) { 
  				parent = p;
  			} else {
  				finished = true;
  			};
  		}

  		return parent;
  	}

def moveTablarHandleActive(part, dir) {
  		my ok = true;
  		if (dir eq 'up') {
	  		ok = not call getPartTypeOben(part, 'ct_haller_shelf_component', Vector(), 5, true);
			if (ok) {
				my volume = ParentOfType(part, 'mainstructure', 'normal_volume');
				my pflanzen = call getAllPflanzenOfVolume(volume);
				my pos = Feature('mountingheight');
				my height = volume ? Feature(volume, 'zlength') : 75;
				my max = 4;
				if (Size(pflanzen)) {
					max = 20;

				}
				ok = (height - pos) gt max;
			}
		} else
		if (dir eq 'down') {
			ok = Feature('mountingheight') gt 2 and Feature('mountingheight') lt 5;
			if (ok) {
				return ok;
			} else {
				return not call getPartTypeOben(part, 'ct_haller_shelf_component', Vector(), -5.1, true);
			};
		}
		return ok;

  	};

def dock_to_cpuhalter_active(part)
{
/**
  check whether the dock to the cpu-halter on the traegerrohr should be active or not
  @param Part the current part
  @retval Boolean activate or deactivate the dock
*/


  my is_auflagerrohr = ParentOfType(part, 'mainstructure', 'auflagerrohrgarnitur');
  my is_neigetisch = FindPart('keilverbinder', 'spannring', 'ct_neigkopfelemente');
  my neigteleskop = FindPart('neigschelle_unten', 'neigteleskopunten');
  my dockindex_on_neigeteleskopachse = (neigteleskop) ? DockGetIndex(DockGetConnectedDock(Dock(neigteleskop, 'teleskop2achse', 0))) : 0;
  my neigeteleksopachse = (neigteleskop) ? DockGetConnectedPart(Dock(neigteleskop, 'teleskop2achse', 0)) : NULL;
  my on_opposite_site_of_neigehebel = (NOT StringContains(GetTypeName(neigeteleksopachse), 'left') AND dockindex_on_neigeteleskopachse EQ 1) OR (StringContains(GetTypeName(neigeteleksopachse), 'left') AND dockindex_on_neigeteleskopachse EQ 2);
  (is_auflagerrohr AND NOT is_neigetisch) OR (NOT is_auflagerrohr AND is_neigetisch AND on_opposite_site_of_neigehebel);
};

