def MyBrokenConnection(trafo) {
/**
  Checkt, ob Leitgestaenge unterbochen sind
  @param long trafo
  @retval List list der nicht verbundenen Leitgestaenge
*/
  my stromkreis= Feature(trafo, 'Stromkreis');
  my forestname= 'mainstructure';
  my forest= Forest(forestname);
  my lg_list_all= ChildrenListOfTypeDeep(forest, 'leitgestaenge');
  lg_list_all= FilterList(lg_list_all, `child`,`Number(Feature(child, 'f_trafo')) EQ trafo;`);
  my lg_list= FilterList(lg_list_all, `child`,`Feature(child, 'Stromkreis') NE stromkreis;`);
  my should= Size(lg_list);

  my d1= Dock(trafo, 'verbinder2lgestaenge', 1);
  my d2= Dock(trafo, 'verbinder2lgestaenge', 2);
  my d3= Dock(trafo, 'verbinder2lgestaenge', 3);

  my lg1= DockGetConnectedPart(d1);
  my lg2= DockGetConnectedPart(d2);
  my lg3= DockGetConnectedPart(d3);

  my con_lg_list= List();

  con_lg_list= call collectLeitgestaenge(con_lg_list, lg1);
  con_lg_list= call collectLeitgestaenge(con_lg_list, lg2);
  con_lg_list= call collectLeitgestaenge(con_lg_list, lg3);

  my has= Size(con_lg_list);

  my fail_list= FilterList(lg_list, `lg`, `InList(con_lg_list, lg);`);
  if (!Defined(fail_list)) {
    fail_list= List();
  };

  /*retval now the failing list*/

  fail_list;

};

def collectLeitgestaenge(lg_list, lg) {
/**
  recursive subroutine to get the failing leitgestaenge
  @param list lg_list the List to be filled
  @param long lg the actual leitgestaenge
  @retval lg_list list the filled lg_list.
*/

  if ( lg AND not InList(lg_list, lg) ) {
    lg_list= JoinList(lg_list, List(lg));

    for(my refnr= 1; refnr LT 3; refnr= refnr +1){
      my lg2v= Dock(lg, 'lgestaenge2verbinder', refnr);
      if (lg2v) {
        my verbinder= DockGetConnectedPart(lg2v);
        if (verbinder AND IsSubTypeOf(verbinder, 'verbinder')) {
          my ver_list= DocksOfType(verbinder, 'verbinder2lgestaenge');
          my size= Size(ver_list);
          for (my i= 0; i LT size; i=i+1) {
            my lgg= DockGetConnectedPart(ver_list[i]);
            if (lgg AND lgg NE lg) {
              lg_list= call collectLeitgestaenge(lg_list, lgg);
            };
          };

        };
      };
    };

  };  
  lg_list;
};

def findTrafoFeature(lg) {
/**
  Sucht das Leitgestaenge, das den Trafo als Feature gesetzt hat oder den Trafo
  selber. Wenn nichts gefunden wird, 0.
  @param long lg das Leitgestaenge
  @retval long den Feature Wert oder 0

*/
  my trafo= FindPart('trafo');
/*  my verbinder= trafo ? 0 : FindPart('verbinder','leitgestaenge');*/
  my v_list= trafo ? 0 : ConnectedDocksOfType(lg, 'lgestaenge2verbinder');
  my f_trafo= 0;

  if (not trafo) {
    my size= Size(v_list);
    for (my i= 0; i LT size; i= i+1) {
      my verbinder= DockGetConnectedPart(v_list[i]);
      my lg_list= verbinder ? ConnectedDocksOfType(verbinder, 'verbinder2lgestaenge') : List();
      my lg_size= Size(lg_list);

      for(my j= 0; j LT lg_size; j= j+1) {
        my lg= DockGetConnectedPart(lg_list[j]);
        f_trafo= Feature(lg, 'f_trafo') +0;
        j= f_trafo GT 0 ? lg_size - 1 : j;
      };
      i= f_trafo GT 0 ? size -1 : i;
    };

  };
  trafo ? trafo : f_trafo;
};

