def checkDeprecatedArticles(part) {
   my answer = FALSE;
   my mypart = '';
   /* For assemblies */
   my list1 = List('quertraeger400','quertraeger750','quertraeger775','quertraeger900','quertraeger925','quertraeger1000');
   my list2 = List('bildschirmschwenkarm420x50','bildschirmplattenset360x330niv','bildschirmplattenset440x420niv','telefonschwenkarm186x580','telefonschwenkarm220x580','telefonschwenkarm220x580','telefonschwenkarm186x420','telefonschwenkarm220x420');
   /* my list3 = List('basistraeger400','basistraeger750','basistraeger775','basistraeger900','basistraeger925','basistraeger1000'); */
   my list3 = List('tischanbau');
   my list = JoinList(list1,list2);
   list = JoinList(list,list3);
   mypart = GetPartTypeName(GetPartType(part));
   if (not InList(list,mypart)) {
    /* For components */
    mypart = '';
