def findChangedMasterdata(artno,attribute,fieldname) {
      my answer = '';
      my name = '';
      my state = '';
      if (InTable(CHANGED, 'Anr', artno)) {
      	state = CHANGED['Anr', artno]['Lieferstatus'];
      };
      if (state eq 'auslauf') {
      	if (attribute eq 'name') {
           name = CHANGED['Anr', artno][fieldname];
           answer = Localize('Auslaufartikel') ++ ': ' ++ name;
         }else{
            answer = CHANGED['Anr', artno][fieldname];
         }
       } else {
        if (not VarDefined('CHANGED_NO_DELIVERY')) {
        	call loadMasterData('no_delivery');
        };
        if (attribute eq 'name') {
          name = CHANGED_NO_DELIVERY['Anr', artno]['Bezeichnung_'++UpperCase(EnvValue('DYNAMIC.Language'))];
          answer = Localize('Nicht mehr im Sortiment:') ++ ' ' ++ name;
        }else{
          if (attribute eq 'weight') {
            answer = CHANGED_NO_DELIVERY['Anr', artno]['Gewicht'];
          }else{
            answer = 99999.99;
          }
        }


       }
    return answer;
  }

