def trimArtikelNummmer(commercial,type) {
    my artno = '99999.99';
    my tmp ='';
    type = Trim(type);  
    /* Wenn Artikel-Type vorhanden ist */
    if ( InTable(commercial, 'type', type) ) {
      /* Artikelnummer definieren */
      artno = Trim(commercial['type', type]['value']);
      if ( EndsWith(artno, ';') ) {
        artno = Eval(artno);
      }
      if (EndsWith(artno,'_xxx')) {
        /* methode with separated date */
        tmp = commercial['type', type]['deprecated'];
        if (StrLen(tmp) gt 4) {
          artno = commercial['type', type]['deprecated'];
        }else{
          /* methode without separated date */
          artno = SubStr(artno,0,8);
        }
        artno;
      }
    } else 
    if (part and type eq 'Gewichtsplatte_Set') {
    	if ((my artnr = call getSafetySet(ChildWithId(part,10)))) {
    		artno = StrLen(artnr) ? artnr : artno;
    	}
    }
    return artno;
  }

def artikelListInfo(commercial,info,variant,type,part) {
    my retval = '';
    my fieldname = '';
    my artno = call trimArtikelNummmer(commercial,type);
    /* fieldname Abfrage definieren */
    if (info eq 'price') {
      fieldname = call artikelCurrency(variant);     
    }else if (info eq 'name') {
      fieldname = call artikelName(variant);
    }else if (info eq 'weight') {
      fieldname = 'Gewicht';
    }else if (info eq 'pcf_amount') {
      fieldname = 'pcf_amount';
    }
    /* Checken ob Changed-Artikel */
    if (InTable(CHANGED,'Anr',artno)) {   
         retval = call findChangedMasterdata(artno,info,fieldname);
         if (info eq 'weight') {
	        retval = Number(retval);
	     }
    }else 
    if (InTable(BASE,'Anr',artno)) { 
	     /* Infos holen aus masterdata */
	       retval = Trim(BASE['Anr', artno][fieldname]);
	      /* Korrekturen */
	      if (info eq 'name' and StrLen(retval) lt 2) {  
	        retval = Trim(BASE['Anr', artno]['Kurzbezeichnung']);
	      }  
	      if (info eq 'weight') {
	        retval = Number(retval);
	      }
      }else {
     	if (not VarDefined('CHANGED_NO_DELIVERY')) {
        	call loadMasterData('no_delivery');
        };
         if (InTable(CHANGED_NO_DELIVERY,'Anr',artno)) {   
	         retval = call findChangedMasterdata(artno,info,fieldname);
	         if (info eq 'weight' or info eq 'pcf_amount') {
		        retval = Number(retval);
		     }
    	} else {
	       /* Wenn Artikel-Type nicht vorhanden ist */
	       if (info eq 'price' or info eq 'weight') {
	          retval = Number(99999.99);
	       }else if (info eq 'name') {
	          retval = type;
	       }
	     }
     }
    return retval;
 }

def checkAuslaufArtikel(commercial,type) {
    my conflict = false;
    my artname = GetTypeName(type);
    my artno = call trimArtikelNummmer(commercial,artname);
    my state = CHANGED['Anr',artno]['Lieferstatus'];
    if ( InTable(CHANGED,'Anr',artno) ) {
      conflict = state eq 'auslauf' or (state eq 'parallel' and not EnvValue('Tab.Use.vitrinehaller'));
      if (conflict) {
      	 if ((artno ~ '.35' or InList(FILTER_AUSLAUF_USM, artno)) and call isUSM()) {
      	 	conflict = false;
      	 };
      };
      /* WriteInfoLog('Auslaufartikel: ' ++ artno ++ ': ' ++ artname); */
    }
    return conflict;
  }

def artikelName(variant) {
	   if (variant eq '1') {
	     variant = 'DE';
	   }else if (variant eq '2') {
	     variant = 'FR';
	   }else if (variant eq '3') {
	     variant = 'EN';
	   }else if (variant eq '4') {
	     variant = 'IT';
	   }else if (variant eq '5') {
	     variant = 'ES';
	   } else{
	     variant = 'DE';
	   }
	   my bezeichnung = 'Bezeichnung_' ++ variant;
	   return bezeichnung;
  }

def artikelCurrency(variant) {
     if (variant eq '1') {
       variant = 'CHF';
     }else if (variant eq '2') {
       variant = 'EUR';
     }else if (variant eq '3') {
       variant = 'USD';
     }else if (variant eq '4') {
       variant = 'alt_CHF';
     }else if (variant eq '5') {
       variant = 'alt_EUR';
     }else if (variant eq '6') {
       variant = 'alt_USD';
     }else if (variant eq '7') {
       variant = 'JPY';
     }else if (variant eq '8') {
       variant = 'alt_JPY';
     }else if (variant eq '9') {
       variant = 'GBP';
     }else if (variant eq '10') {
       variant = 'alt_GBP';
     }else if (variant eq '11') {
       variant = 'CNY';
     }else if (variant eq '12') {
       variant = 'alt_CNY';
     } else{
       variant = 'CHF';
     }
     my preis = 'Preis_' ++ variant;
     return preis;
  }

def tisch_i_match(tda,laenge,breite){
  my match = false;
  my plaenge = Number(Feature(tda,'f_laenge'));
  my pbreite = Number(Feature(tda,'f_breite'));
  if (laenge eq plaenge and breite eq pbreite) {
   match = true;
  }else if (breite eq 'all' and laenge eq plaenge) {
   match = true;
  }else if (laenge eq 'all' and breite eq pbreite) {
   match = true;
  };  
  match;
};

def indexList(start,step,size) {
      my list = List();
      for ( my i = 0; i lt size; i=i+1) {
       list = ListAdd(list, start);
       start = start + step;
      }
      list;
    };

