      }
      retval;
    }
    if (property eq 'trafoModell'){
    	if (NOT InList(countrylist, country)) {
          retval = 'trafoE-eu';
      } else if (country eq 'CH') { 
        retval = 'trafoE-eu';
      } else if (country eq 'CN') { 
