      } else if (country eq 'AU') { 
        retval = 'trafoE-au';
      } else if (country eq 'NZ') { 
        retval = 'trafoE-au';
      } else if (country eq 'GB') { 
        retval = 'trafoE-uk';
      } else if (country eq 'HK') { 
        retval = 'trafoE-uk';
      } else if (country eq 'SG') { 
        retval = 'trafoE-uk';
      } else if (country eq 'AE') { 
        retval = 'trafoE-uk';
      } else if (country eq 'QA') { 
        retval = 'trafoE-uk';
      } else if (country eq 'US') { 
        retval = 'trafoE-us';
      } else if (country eq 'CA') { 
        retval = 'trafoE-us';
      } else if (country eq 'MX') { 
        retval = 'trafoE-us';
      } else if (country eq 'JP') { 
        retval = 'trafoE-jp';
      } else if (country eq 'TW') { 
