      } else if (country eq 'KR') { 
        retval = 'trafoE-kr';
      } else if (InList(eulist, country)) { 
        retval = 'trafoE-eu';
      }
      retval;
    }

    if (property eq 'griffArt') {
      existing = Property('griffArt');
      if (country eq 'JP' and existing ne 'schnapp_griff_normal') {
        retval = 'schnapp_griff_normal';
      } else {
