        retval = 'hoch';
      } else { 
        retval = 'niedrig';
      }
      retval;
     }  

     retval;
  }

def befestigungsSetGlasSchloss(part) {
    my befset = 'glas-glas';
    my setpart = null;
    my verkleidung = null;
    my scharnier = null;
    my dist = 0;
    my distmin = 999;
    my restlist = List();
    my setpartline = List();
    my line = List();
    scharnier = FindPart(part,'glastuer','scharnier');
    my volume = MainRoot(part);
    my list = GetVolumeRefParts(volume);
    /* Filtert die Verkleidungskandidaten raus*/
    list = FilterList(list,'element',`not IsSubTypeOf(element,'verkleidung');`);
    list = FilterList(list,'element',`not call vertikalVerkleidung(element);`);
    /* welcher ist am naechsten zum Scharnier */
    for (my verkleidung : list ) {
     my relpos = RelativePartPos(scharnier, verkleidung);
     dist = VectorLength(relpos);
     if (dist lt distmin and dist gt 0) {
       distmin = dist;
       setpart = verkleidung;
     }
    }
    /* Message(GetTypeName(setpart)); */
    /* welcher ist am naechsten zum Schloss, parallele Verkleidung */
    restlist = FilterList(list,'element',`element eq setpart;`);
    setpartline = call globalNormal(setpart);
    for (my verkleidung : restlist) {
     line = call globalNormal(verkleidung);
     if (LinesAreParallel(setpartline, line)) {
       setpart = verkleidung;
     }
    }
    /* Verkleidungstyp ergibt Art des Befestigungsset */
    if (IsSubTypeOf(setpart,'metallverkleidung')) {
      befset = 'glas-metall';
    }
    return befset;
    }

def globalColorWeb(partlist) {
      my blechlist = FilterList(partlist,'element',`element['type'] ne 'blech';`);
      my colorlist = List();
      my basecolor = 0;
      my max = 0;
      my color = '';
      my colorlist = List(basecolor);
      for (my blech : blechlist) {
          color = Number(blech['property']['name','material']['value']);
          colorlist[color] = colorlist[color] + 1;
      }

      max = ListMax(colorlist);

      for (my i : IndexList(colorlist)) {
        if (colorlist[i] eq max) {
          color = i;
          break;
        }
      }
      return color;
      }

def globalNormal(p) {
    /* moeglich zB. auch Vector(0,0,111) und Vector(0,0,222) */
	  my v1 = GlobalPos(p, Vector(0,0,0));
	  my v2 = GlobalPos(p, Vector(0,0,1));
	  return Line(v1, VectorSub(v2, v1));
	}

def globalNormalY(p) {
    /* moeglich zB. auch Vector(0,0,111) und Vector(0,0,222) */
    my v1 = GlobalPos(p, Vector(0,0,0));
    my v2 = GlobalPos(p, Vector(0,1,0));
    return Line(v1, VectorSub(v2, v1));
  }

def checkAsymTischEinsaeulig(tischblatt) {
			my asym = false;
			my tisch = Parent('mainstructure',tischblatt);
			if (tisch) {
			  if (IsSubTypeOf(tisch,'einsaeuliger_tisch')) {
					my list = ChildrenListOfTypeDeep(tisch,'auflagerrohrgarnitur');
					my base = GetPartType(list[0]);
					for (my i = 0; i lt Size(list); i = i +1) {
					     if (base ne GetPartType(list[i])) {
					       asym = true;
					       break;
					     }
					}
				}
			}
			return asym;			
			}

def checkAsymTischZweisaeulig(tischblatt) {
      my asym = false;
      my asym1 = false;
      my asym2 = false;
      my tisch = Parent('mainstructure',tischblatt);
      my list = List();
      my ag300 = 0;
      my ag375 = 0;
      my ag450 = 0;

      if (tisch) {
        if (IsSubTypeOf(tisch,'zweisaeuliger_tisch')) {
             list = ChildrenListOfTypeDeep(tisch,'auflagerrohrgarnitur');
          ag300 = ChildCount(tisch,'auflagerrohrgarnitur300');
          ag375 = ChildCount(tisch,'auflagerrohrgarnitur375');
          ag450 = ChildCount(tisch,'auflagerrohrgarnitur450');
          if (PartAttr(part,'length') eq 150) {
          asym1 = ag300 eq 1 and ag375 eq 4 and ag450 eq 1;
          asym2 = ag300 eq 3 and ag450 eq 3;
          asym = asym1 or asym2;
        } else if (PartAttr(part,'length') eq 175) {
            asym1 = ag300 eq 3 and ag375 eq 0 and ag450 eq 3;
            asym2 = ag300 eq 1 and ag375 eq 4 and ag450 eq 1;
            asym = asym1 or asym2;
          }
        }
      }

      return asym;      
      }

