def checkTischklappe(check) {

    my forestpartlist = GetSelectedPartList('mainstructure');
    my partlist = List();
    my proplist = List();
    my propstring = '';
    my retval = false;

    for (my i=0; i lt Size(forestpartlist); i=i+1) {
        /* Tische i */
        if (PropertyActive(forestpartlist[i], 'pr_tischklappenvariante_L_top')){
          partlist = ListAdd(partlist,forestpartlist[i]);
        /* Tische i mit Zubehoer */
        }else if (Bool(ChildOfType(forestpartlist[i],'at_tisch_i_einheit'))) {
          partlist = ListAdd(partlist,ChildOfType(forestpartlist[i],'at_tisch_i_einheit'));
        }else if (Bool(ChildOfType(forestpartlist[i],'at_tisch_e_einheit'))) {
          partlist = ListAdd(partlist,ChildOfType(forestpartlist[i],'at_tisch_e_einheit'));
        }else if (Bool(ChildOfType(forestpartlist[i],'at_tisch_m_einheit'))) {
          partlist = ListAdd(partlist,ChildOfType(forestpartlist[i],'at_tisch_m_einheit'));
        }else{
        /* Normale Tische */
          partlist = ListAdd(partlist,ChildOfTypeDeep(forestpartlist[i], 'tisch_75_std'));
          partlist = ListAdd(partlist,ChildOfTypeDeep(forestpartlist[i], 'tisch_100_std'));
          partlist = ListAdd(partlist,ChildOfTypeDeep(forestpartlist[i], 'tisch_75_sondergroesse'));
          partlist = ListAdd(partlist,ChildOfTypeDeep(forestpartlist[i], 'tisch_100_sondergroesse'));
        }
     }

    if (check eq 'aussen') {
    my list = PropertyValuesFromPartList(partlist, 'pr_tischklappenvariante_L_top');
    proplist = PropertyValuesFromPartList(partlist, 'pr_tischklappenvariante_R_top');
    proplist = JoinList(list,proplist);
    }

    if (check eq 'R_aussen') {
    my list = PropertyValuesFromPartList(partlist, 'pr_tischklappenvariante_RL_top');
    proplist = PropertyValuesFromPartList(partlist, 'pr_tischklappenvariante_RR_top');
    proplist = JoinList(list,proplist);
    }

    if (check eq 'R_innen') {
    proplist = PropertyValuesFromPartList(partlist, 'pr_tischklappenvariante_RM_top');
    }

    propstring = DumpToString(proplist);
    retval = not (StringContains(propstring,'_vorne') or StringContains(propstring,'_hinten')) ;

  }

def checkAllMounted(part) {
    my partlist = GetSelectedComponentList('mainstructure');
    my proplist = PropertyValuesFromPartList(partlist, 'mounted');
    my propstring = DumpToString(proplist);
    my allmounted = not (StringContains(propstring,'false'));
    /* check Zubehoer */
    my zubehoer = false;
    my selected = GetSelectedPart('mainstructure');
    if (selected) {
         my name = GetTypeName(selected);
      my parent = Parent('mainstructure',selected);
      my pname  = GetTypeName(parent);
      if (StringContains(name,'zubehoer') or StringContains(pname,'zubehoer')) {
       zubehoer = true;
      }
    }
    return allmounted and not zubehoer;
    }

def checkManuellMovable(part, param) {
   my retval = '';
   my tisch = GetTypeName(part);

   if (param eq 'up') {
     if (tisch ne 'as_tisch_m_meeting') {
        retval = Feature(part,'f_hoehe_vario_top') lt 1200;
     } else {
        retval = Feature(part,'f_hoehe_vario_top') lt 1150;
     }
   }

   if (param eq 'down') {
     retval = Feature(part,'f_hoehe_vario_top') gt 700;
   }

   if (param eq 'min') {
     retval = 70;
   }

   if (param eq 'max') {
     if (tisch ne 'as_tisch_m_meeting') {
        retval = 120;
     } else {
        retval = 115;
     }
   }   
   retval;
  }

def checkElectricMovable(part, param) {
   my type = '';
   my trav = '';
   my retval = '';
   if (PropertyActive(part, 'pr_saeulenpaar_top')) { 
      type = Feature(part,'f_saeulenpaar_top');
      trav = Feature(part,'f_traverse_e1_top');
    }else{
      type = Feature(ChildOfTypeDeep(part,'at_tisch_e_main'),'f_saeulenpaar_top');
      trav = Feature(ChildOfTypeDeep(part,'at_tisch_e_main'),'f_traverse_e1_top');
    }

   if (param eq 'movable') {
     if (type eq 'saeulenpaar_e2' or type eq 'saeulenpaar_e3') { retval = true; }else{ retval = false; };
   }

   if (param eq 'change') {
     if (Bool(trav)) { retval = true; }else{ retval = false; };
   }

   if (param eq 'up') {
     if (type eq 'saeulenpaar_e2') { retval = Feature(part,'f_hoehe_vario_top') lt 1200;};
     if (type eq 'saeulenpaar_e3') { retval = Feature(part,'f_hoehe_vario_top') lt 1300;};
   }

   if (param eq 'down') {
     if (type eq 'saeulenpaar_e2') { retval = Feature(part,'f_hoehe_vario_top') gt 700;};
     if (type eq 'saeulenpaar_e3') { retval = Feature(part,'f_hoehe_vario_top') gt 650;};
   }

   if (param eq 'min') {
     if (type eq 'saeulenpaar_e1') { retval = 74;};
     if (type eq 'saeulenpaar_e2') { retval = 70;};
     if (type eq 'saeulenpaar_e3') { retval = 65;};
   }

   if (param eq 'max') {
     if (type eq 'saeulenpaar_e1') { retval = 74;};
     if (type eq 'saeulenpaar_e2') { retval = 120;};
     if (type eq 'saeulenpaar_e3') { retval = 130;};
   }

   retval;
  }

def checkMovable(part, param) {
   my retval = '';
   my tisch = GetTypeName(part);

   if (StringContains(tisch,'tisch_e') ) {
     retval = call checkElectricMovable(part, param);
   } else if (StringContains(tisch,'tisch_m')) {
      retval = call checkManuellMovable(part, param);
   }
   return retval;
 }

def postSelection(selected,width) {

    my root = Forest('mainstructure');
    my inputlist = List();
    if (width le 75) {inputlist = ChildrenListOfTypeDeep(root, 'tisch_einheit_75');};
    if (width eq 100) {inputlist = ChildrenListOfTypeDeep(root, 'tisch_einheit_100');};
    my list = List();
    my size = Size(inputlist);
    my start = size - selected;
    for (my i = start; i lt size; i = i+1) {
     list = ListAdd(list, inputlist[i]);
    };
    list;
  }

def checkDockActive(param1,param2) {
my active = false;
my sp_1= FindPart('rohr2keil', '1', 'spannring');
my sp_2= FindPart('rohr2keil', '2', 'spannring');
my checkIndex_1= PartRot()['z'] EQ 90 AND PartRot(sp_1)['z'] EQ 0 ? param1 : param2;
my checkIndex_2= PartRot()['z'] EQ 90 AND PartRot(sp_2)['z'] EQ 0 ? param1 : param2;    

if (sp_1 AND sp_2) {
  my A = Bool(FindPart(sp_1, 'ring2keil', checkIndex_1));
  my B = Bool(FindPart(sp_2, 'ring2keil', checkIndex_2));
  active = A and B;
}
return active;
  };

