def centerPart(direction) { 
      my trans = 0;
      my lpos = PartPos(part);
      my gpos = GlobalPos(part, lpos);
      my gposdir =Round(gpos[direction]);
      if(gposdir gt 0) {
        trans = (0 - gposdir)/2;
      }else{
        trans = (0 - lpos[direction])/2;
      };
      trans;
  }

def redTischMaterial(part) { 
      my A = Bool(FindPart(part,'ct_tischblende_quer'));
      my B = Bool(FindPart(part,'ct_kabelrost_i'));
      my C = call zargeWithCPU(part);
      my D = Bool(Feature('f_klappentischblatt'));
      my E = Bool(PartAttr(part, 'type') eq 'esstisch');
      return A or  B or C or D or E;
  }

def redTischMaterialKitos(part) {
      my parent = Parent('mainstructure'); 
      my A = IsSubTypeOf(part, 'rundtischblatt') and Bool(ChildOfType(parent,'tischgestell_apero'));
      my B = IsSubTypeOf(part, 'ct_secksecktischblatt');
      my C = Bool(GetTypeName(part) eq 'tischblatt750x750') and Bool(ChildOfType(parent,'tischgestell_apero')) and Bool(ChildOfTypeDeep(parent,'auflagerrohrgarnitur450'));
      my D = IsSubTypeOf(part, 'standardtischblatt_2s_4eck') and (Bool(Property(parent,'hc_saeulen') eq 'saeule_B2') or Bool(Size(FreeDocksOfType(part, 'dt_tischblatt_2_konsole')) ne 2));
      my E = IsSubTypeOf(part, 'standardtischblatt_1o2s') and Bool(Property(parent,'hc_saeulen') eq 'saeule_B2');
      my F = Bool(Feature(part,'f_asymTischEinsaeulig'));
      my G = Bool(Feature(part,'f_asymTischZweisaeulig'));
      my H = IsSubTypeOf(part, 'tischblatt900x750') and ParentOfType(part, 'mainstructure', 'einsaeuliger_tisch');
      return A or B or C or D or E or F or G or H;
  }

def checkMaterialSubKategorie(part,subkat) { 
      my retval = true;
      my redpart = false;
      my cartridge = GetCartridge(part);
      my weichkat = List('kelco','holz','mdf','linoleum','fenix');
      my hartkat = List('glas','buntglas','mattglas','stein');
      if (cartridge eq 'usm_hallertisch') {
         redpart = IsSubTypeOf(part, 'tisch_100_60dreieck') or IsSubTypeOf(part, 'tisch_100_90dreieck') or
                   IsSubTypeOf(part, 'tisch_75_60dreieck') or IsSubTypeOf(part, 'tisch_75_90dreieck') or
                   IsSubTypeOf(part, 'tisch_100_trapez') or IsSubTypeOf(part, 'tisch_75_trapez') or
                   IsSubTypeOf(part, 'tisch_100_sondergroesse') or IsSubTypeOf(part, 'tisch_75_sondergroesse') or 
                   IsSubTypeOf(part, 'at_tisch_i_main') or IsSubTypeOf(part, 'tisch_mit_zubehoer') or 
                   call redTischMaterial(part);
         	if (IsSubTypeOf(part, 'tischblatt_125_50')) {
         		retval = InList(List('kelco','linoleum','fenix'), subkat);
         	}
     } else if (cartridge eq 'usm_kitos') {
       redpart = IsSubTypeOf(part, 'at_tisch_e') or IsSubTypeOf(part, 'at_tisch_m_main') or call redTischMaterialKitos(part);
     }
     if (redpart and InList(hartkat,subkat) ) {
       retval = false;
     }
     return retval;
  }

def defaultMaterial(part,propertychanged) {
       my changed = Property(part,propertychanged);
