def mountTDAList() {
			my list = GetSelectedPartList('mainstructure');
			my foundlist = List();
			my foundpart = Null;
			for (my i = 0; i lt Size(list); i = i + 1) {
			  if ( IsSubTypeOf(list[i],'at_tisch_e_einheit') or IsSubTypeOf(list[i],'at_tisch_m_einheit')) {
			   foundlist = ListAdd(foundlist, list[i]);
			  }
			  if (GetTypeName(list[i]) eq 'as_tisch_e_mit_zubehoer') {
			     foundpart = ChildOfType(list[i], 'at_tisch_e_main');
			     foundlist = ListAdd(foundlist, foundpart);
			  }
			  if (GetTypeName(list[i]) eq 'as_tisch_m_mit_zubehoer')  {
			     foundpart = ChildOfType(list[i], 'at_tisch_m_main');
			     foundlist = ListAdd(foundlist, foundpart);
			  }
			}

			return foundlist;
		}

def oldDocument() { 
      my oldversion = false;
      my cartridgeversion = '0.0.0';
      my documentversion = '0.0.0';
      my cartridgelist = Document_CartridgeList();
      for (my i=0; i lt Size(cartridgelist); i= i+1) {
        cartridgeversion = CartridgeVersion(cartridgelist[i]);
        documentversion = Document_CartridgeVersion(cartridgelist[i]);
        if (cartridgeversion ne documentversion ) {
          oldversion = true;
        }
      }
      oldversion;
      }

def cleanAuslaufArtikel(commercial) { 
      my article = '';
			my auslauf = '';
			my auslauflist = List();

			for (my i = 0; i lt Size(commercial); i = i + 1) {
			  article = commercial[i]['value'];
			  for (my j = 0; j lt Size(CHANGED); j = j + 1) {
			    auslauf = CHANGED[j]['Anr'];
			    if (article eq auslauf) {
			      auslauflist = ListAdd(auslauflist,auslauf);
			    }
			  }
			}
			return auslauflist;
    }

def checkMeetingTischklappen(meetingtisch,side,mode) { 
      my tisch = Null;
      my retval = '';
      if (mode eq 'tisch') {
        retval = tisch;
      }
      if (side eq 'R') {
         if (EndsWith(Property(meetingtisch,'pr_tischklappenvariante_R_top'),'_hinten')) {
           if (mode eq 'tisch') {
              retval = meetingtisch;
           } else if (mode eq 'feature') { 
             retval = 'Klappe_gross_innen';
           } 
         } else  if (EndsWith(Property(meetingtisch,'pr_tischklappenvariante_R_top'),'_vorne')) {
           if (mode eq 'tisch') {
              retval = meetingtisch;
           } else if (mode eq 'feature') { 
             retval = 'Klappe_gross_aussen';
           } 
         }   
      } else if (side eq 'L') {
        if (EndsWith(Property(meetingtisch,'pr_tischklappenvariante_L_top'),'_hinten')) {
           if (mode eq 'tisch') {
              retval = meetingtisch;
           } else if (mode eq 'feature') { 
             retval = 'Klappe_gross_aussen';
           } 
         } else  if (EndsWith(Property(meetingtisch,'pr_tischklappenvariante_L_top'),'_vorne')) {
           if (mode eq 'tisch') {
              retval = meetingtisch;
           } else if (mode eq 'feature') { 
             retval = 'Klappe_gross_innen';
           } 
         }   
       }   
      return retval;
   }

