def sperrstangenConnectedMountStatus(part) { 
    my mount = 'true';
    my dockOben = null;
    my dockUnten = null;
    my teleskopOben = null;
    my teleskopUnten = null;
    my mountOben = '';
    my mountUnten = '';

    if (part) {
      dockOben = Dock(part,'sperrstange_oben2teleskop','1');
      dockUnten = Dock(part,'sperrstange_unten2teleskop','1');
      teleskopOben = DockGetConnectedPart(dockOben);
      teleskopUnten = DockGetConnectedPart(dockUnten);

      if (teleskopOben and teleskopUnten) {

        mountOben = Feature(teleskopOben,'Mounted');
        mountUnten = Feature(teleskopUnten,'Mounted'); 

        if (mountOben ne mountUnten) {       
        mount = 'false';
        } 
        mount;
      } 
     mount;
    }
    return mount; 
  }

def sperrstangenMountStatus(movedpart,part) { 
    my state = List();
    state[0] = 'true';
    state[2] = Feature(movedpart,'montageid');
    state[3] = Feature(movedpart,'mid');
    my posz = PartPos(part)['z'];
    my deltaz = 9999;
    my distz = 0;
    my refrohr = null;
    my rohre = List();
    if (Feature(movedpart,'Mounted')) {
      rohre = GetComponentListOfConnectionId(ConnectionId(part));
      rohre = FilterList(rohre,'element',`not IsSubTypeOf(element,'normalrohr');`);
      rohre = FilterList(rohre,'element',`call horizontalPart(element);`);
      rohre = FilterList(rohre,'element',`Abs(RelativePartPos(part,element)['x']) gt 4;`);
      rohre = FilterList(rohre,'element',`Abs(RelativePartPos(part,element)['y']) gt 4;`);
      if (Bool(Size(rohre))) {
        for (my rohr : rohre) {
          /* sucht rohr auf moeglichst selber Hoehe */ 
          distz = Abs(RelativePartPos(part,rohr)['z']);
          if (distz lt deltaz) {
             refrohr = rohr;
             deltaz = distz;
          }
        }         

        if (refrohr) {
          state[0] = Feature(refrohr,'Mounted');
          state[2] = Feature(refrohr,'montageid');
          state[3] = Feature(refrohr,'mid');
        }
      }
    } else {
      state[0] = 'false';
    }
    if (state[0] and StrLen(state[2]) gt 0) {
    /* additional check with the connected teleskopauszuege */
    /* Montiert und eine Montage-ID ist vorhanden */
      state[0] = call sperrstangenConnectedMountStatus(part);
      /* wenn unmoniert, dann montageid x.0 und mid auf 0 setzen */
      if (not state[0]) {
         state[2] = StringToList(state[2],'.')[0] ++ '.' ++ '0';
         state[3] = '0';
      }
    }
    return state; 
  }

def aztSperrstangen(part) {
		my sperrstangen = List();
		my teleskop = null;
		my sperrstange = null;
		my dock = '';
		for (my i : List(1,2)) {
		  teleskop = FindPart(part,'tablar2teleskop',i);
		  if (teleskop) {
			  for (my slot : List('oben','unten')) {
			    dock = 'teleskop2sperrstange_' ++ slot;
			    sperrstange = FindPart(teleskop,dock);
				  if (sperrstange) { 
				     sperrstangen = ListAdd(sperrstangen,sperrstange);
				  }
			  }
			};
		 }
		 sperrstangen;
	 }

