def flexBuegelDockPos(part,direction) {
    my pos = 0;
    my angle = Round(GetDOFValue(DockGetConnectedDock(Dock('flex_2_fix'))),0.1);
    my headings = List('angle','y','z');
    my list1 = List('27.4','-4.8','25.9');
    my list2 = List('13.7','-5.2','24.7');
    my list3 = List('0','-5.4','23.4');
    my list4 = List('-13.7','-5.3','22.1');
    my list5 = List('-27.4','-4.9','20.9');
    my values = JoinList(list1, list2);
    values = JoinList(values, list3);
    values = JoinList(values, list4);
    values = JoinList(values, list5);
    my positions = CreateTable(headings, values);
    pos = positions['angle',angle][direction];
    return pos;
  }

def inListOfSubTypes(part,subtypes) {
    my state = false;
    my size = Size(subtypes);
    for (my j = 0; j lt size; j = j + 1) {
      if (IsSubTypeOf(part,subtypes[j]) ) {
        state = true;
        break;
      }    
    }
    return state;
  }

