def separatePossible() {
    my possible = List();
    my valid = true;
    my vol = null;
    my refvols = List();
    my regalvols = List();
    my refvol = null;
    my vselection = true;
    my hselection = true;
    my posx =  Vector();
    my posy =  Vector();
    my posz = Vector();
    my connection_id = '';
    my connected_parts = List();
    my kugeln = List();
    my volumes = GetSelectedPartList('mainstructure');
    volumes = FilterList(volumes,'element',`not IsSubTypeOf(element,'normal_volume');`);
    my size = Size(volumes);

    if (Bool(size)) {
      posx = Round(PartPos(volumes[0])['x']);
      posy = Round(PartPos(volumes[0])['y']);
      posz = Round(PartPos(volumes[0])['z']);
      connection_id = ConnectionId(volumes[0]);
      connected_parts =GetComponentListOfConnectionId(connection_id);
      kugeln = FilterList(connected_parts,'element',`not IsSubTypeOf(element,'kugel_std');`);

      /* Alle Faecher,Volumen im Regal */
      for (my kugel : kugeln) {
        refvols = GetRefVolumes(kugel, 'mainstructure');
        for (my refvol : refvols) {
          if (not InList(regalvols, refvol)) {
            regalvols = ListAdd(regalvols,refvol);
          }
        }
      }

      /* Spezialfall nur ein Volumen ist selektiert */
      if (size eq 1) {
        for (my vol: regalvols) {
          if (Round(PartPos(vol)['z']) ne posz and Round(PartPos(vol)['x']) ne posx) {
            valid = false;
            break;
          }
        }
      } else {       
        /* Horizontale Selektion */
        for (my vol: volumes) {
          if (Round(PartPos(vol)['z']) ne posz) {
            hselection = false;
            break;
          }
        }
         /* Vertikale Selektion */
        for (my vol: volumes) {
          if (Round(PartPos(vol)['x']) ne posx or Round(PartPos(vol)['y']) ne posy) {
            vselection = false;
            break;
          }
        }
        /* Sind alle Faecher in der Hoehe oder in der Breite selektiert */
        if (vselection) {
          for (my vol : regalvols) {
            if (not InList(volumes, vol) and (Round(PartPos(vol)['x']) eq posx and Round(PartPos(vol)['y']) eq posy)) {
              valid = false; 
              break;
            }
          }
        }
        if (hselection) {
          for (my vol : regalvols) {
            if (not InList(volumes, vol) and Round(PartPos(vol)['z']) eq posz) {
              valid = false;
              break;
            } 
          }
        }
      }
      if (not vselection and not hselection) {
        valid = false;
      }
    } else {
      valid = false;
    }
    possible[0] = valid;
    possible[1] = vselection;
    possible[2] = hselection;
    possible[3] = volumes;
    possible[4] = regalvols;
    return possible;
  }

def tischMaterialKategorieMix() {
    my conflicts = List(); 
    my tischblaetter = List();
    my kategorie = '';
    my subkategorie = '';
    tischblaetter = GetComponentListOfType('tischblatt');
    for (my blatt : tischblaetter) {      
      if (blatt) {
        kategorie = Feature(blatt,'f_materialKategorie');
        subkategorie = Feature(blatt,'f_materialSubKategorie');
       if ((subkategorie eq 'buntglas' or subkategorie eq 'mattglas') and subkategorie ne kategorie) {
         conflicts = ListAdd(conflicts,blatt);
       }
      }
    }
    return conflicts;
    }

def vertikalRohrNichtVerbunden() {
    my conflicts = List(); 
    my rohre = List();
    my rohr = null;
    my kugel1 = null;
    my kugel2 = null;
    my kugel = false;
    my hoehe = 0;
    my hoehe1 = 0;
    my hoehe2 = 0;
    my diff1 = 0;
    my diff2 = 0;
    my dist = 0;
    my range1 = false;
    my range2 = false;
    rohre = GetComponentListOfType('rohr');
    /* Gewindehilfsrohre sind innere Hilfsrohre, die intern gedockt sind  */
    rohre = FilterList(rohre,'element',`IsSubTypeOf(element,'gewindehilfsrohr');`);
    rohre = FilterList(rohre,'element',`call horizontalPart(element);`);
    for (my rohr : rohre) {      
      if (rohr) {
        hoehe = PartPos(rohr)['z'];
        dist = Round(PartAttr(rohr,'hc_length')/20,0.1);
        kugel1 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
        kugel2 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',2));
        /* wegen bibliozapfen muss der Typ auch ueberprueft werden */
        kugel = IsSubTypeOf(kugel1,'kugel') and IsSubTypeOf(kugel2,'kugel');
       if (kugel1 and kugel2 and kugel) {
         hoehe1 = PartPos(kugel1)['z'];
         hoehe2 = PartPos(kugel2)['z'];
         diff1 = Round(Abs(hoehe - hoehe1),0.1);
         diff2 = Round(Abs(hoehe - hoehe2),0.1);
         range1 = InRange(diff1 - 0.2,diff1 + 0.2,dist);
         range2 = InRange(diff2 - 0.2,diff2 + 0.2,dist);
         /* Message(dist ++ ', ' ++ diff1 ++ ', ' ++ diff2); */
         if (not range1 or not range2) {
           conflicts = ListAdd(conflicts,rohr);
         } 
       }
      }
    }
    return conflicts;
    }

def volumeIsRotated(part) {
    my rotated  = true;
    my rohr = null;
    my kugel1 = null;
    my kugel2 = null;
    my pos1 = Vector();
    my pos2 = Vector();
    my diffx = 0;
    my diffy = 0;
    my horizontal_rohre = List();
    horizontal_rohre = FilterList(GetVolumeRefParts(part),'element',`not IsSubTypeOf(element,'rohr');`);
    horizontal_rohre = FilterList(horizontal_rohre,'element',`not call horizontalPart(element);`);
    rohr = horizontal_rohre[0];
    if (rohr) {
      kugel1 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
      kugel2 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',2));
      if (kugel1 and kugel2) {
        pos1 = PartPos(kugel1);
        pos2 = PartPos(kugel2);
        diffx = pos1['x'] - pos2['x'];
        diffy = pos1['y'] - pos2['y'];
        diffx = Abs(Round(diffx,1));
        diffy = Abs(Round(diffy,1));
		    if (not diffx or not diffy) {
		      rotated = false;
		    }
		  }
    }
    return rotated;
  }

def volumeInDirectionY(part) {
    my direction_y  = false;
    my rohr = null;
    my kugel1 = null;
    my kugel2 = null;
    my pos1 = List();
    my pos2 = List();
    my diffx = 0;
    my diffy = 0;
    my horizontal_rohre = List();
    horizontal_rohre = FilterList(GetVolumeRefParts(part),'element',`not IsSubTypeOf(element,'rohr');`);
    horizontal_rohre = FilterList(horizontal_rohre,'element',`not call horizontalPart(element);`);
    horizontal_rohre = FilterList(horizontal_rohre,'element',`Bool(Abs(PartRot(element)['z']));`);
    horizontal_rohre = FilterList(horizontal_rohre,'element',`Bool(Abs(PartRot(element)['x']));`);
    horizontal_rohre = FilterList(horizontal_rohre,'element',`not Bool(Abs(PartRot(element)['y']));`);
    if (Bool(Size(horizontal_rohre))) {
      rohr = horizontal_rohre[0];
      kugel1 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
      kugel2 = DockGetConnectedPart(Dock(rohr,'rohr2kugel',2));
      if (kugel1 and kugel2) {
        pos1 = RelativePartPos(rohr,kugel1);
        pos2 = RelativePartPos(rohr,kugel2);
        diffx = pos1['x'] - pos2['x'];
        diffy = pos1['y'] - pos2['y'];
        diffx = Bool(Abs(Round(diffx,1)));
        diffy = Bool(Abs(Round(diffy,1)));
        if (not diffx and diffy) {
          direction_y = true;
        }
      }
    }
    return direction_y;
  }

def blechName(comptype,type,width,depth) { 
       my blechname = '';
       my list1 = List('blech250_100','blech250_150','blech250_175','blech250_250','blech250_350','blech250_395','blech250_500','blech250_750');
       my list2 = List('blech350_100','blech350_150','blech350_175','blech350_350','blech350_395','blech350_500','blech350_750');
       my list3 = List('blech395_100','blech395_150','blech395_175','blech250_395','blech395_395','blech500_100');
       my list4 = List('blech500_150','blech500_175','blech500_395','blech500_500','blech500_750');
       my list5 = List('kurzblech350_395','kurzblech500_395','kurzblech750_395','kurzblech350_500','kurzblech350_750','kurzblech500_500','kurzblech500_750');
       my list6 = List('blech750_100','blech750_150','blech750_175','blech750_395');
       my blechlist = JoinList(list1,list2);
       blechlist = JoinList(blechlist,list3);
       blechlist = JoinList(blechlist,list4);
       blechlist = JoinList(blechlist,list5);
       blechlist = JoinList(blechlist,list6);
       /* compose component name: blech normal */
       if (type eq 'normal') {
         blechname = comptype ++ depth ++ '_' ++ width;
         if (not InList(blechlist,blechname)) {
           blechname = comptype ++ width ++ '_' ++ depth;
         }
       /* compose component name: blech gelocht */
       } else if (type eq 'gelocht') {
           list1 = List('lochblech100_350','lochblech175_500','lochblech250_100','lochblech250_125','lochblech250_150','lochblech250_175','lochblech250_200','lochblech250_250','lochblech250_350','lochblech250_500');
           list2 = List('lochblech275_250','lochblech350_125','lochblech350_150','lochblech350_175','lochblech350_200','lochblech350_275','lochblech350_350','lochblech350_395','lochblech350_500');
           list3 = List('lochblech395_125','lochblech395_350','lochblech395_500','lochblech500_500','lochblech750_125','lochblech750_350');
           list4 = List('lochblech500_100','lochblech500_125','lochblech500_150','lochblech500_200','lochblech500_275','lochblech550_350');
           blechlist = JoinList(list1,list2);
		       blechlist = JoinList(blechlist,list3);
		       blechlist = JoinList(blechlist,list4);
           blechname = 'loch' ++ comptype ++ width ++ '_' ++ depth;
            if (not InList(blechlist,blechname)) {
	            blechname = 'loch' ++ comptype ++ depth ++ '_' ++ width;
	          }
       } else if (type eq 'gegengewicht') {
          blechlist = List('blech750_395_ggw','blech500_395_ggw','blech350_750_ggw','blech500_750_ggw');
          blechname = comptype ++ depth ++ '_' ++ width ++ '_ggw';
         if (not InList(blechlist,blechname)) {
           blechname = comptype ++ width ++ '_' ++ depth ++ '_ggw';
         }
       }
       return blechname;
     }

