def importComponentType(part) { 
     my comptype = '';
     my width = '';
     my depth = '';
     my height = '';
     my length = '';
     my side = '';
     my type = '';
     my uscore = '_';

     comptype = part['type'];

     if (part['property']) {
       width = part['property']['name','width']['value'];
       depth = part['property']['name','depth']['value'];
       height = part['property']['name','height']['value'];
       length = part['property']['name','length']['value'];
       side = SubStr(part['property']['name','side']['value'],0,1);
       type = part['property']['name','type']['value'];
     }

     if (comptype eq 'fuss'){
       comptype = 'hallerfuss';
     } else if (comptype eq 'volumeconnector') {
       comptype = 'volcontconnector';
     } else if (comptype eq 'kugel') {
       comptype = 'kugel_std';
     } else if (comptype eq 'klemmhalter') {
       comptype = 'stdklemmhalter';
     } else if (comptype eq 'durchlass') {
       comptype = 'blechausschnitt';
     } else if (comptype eq 'rohr') {
       comptype = comptype ++ width;
     } else if (comptype eq 'teleskopauszug') {
       comptype = comptype ++ depth ++ uscore ++ side;
     } else if (comptype eq 'tablarseitenwinkel') {
       comptype = comptype ++ depth ++ uscore ++ side;
     } else if (comptype eq 'ausziehtablar') {
        if (type eq 'inverse') {
            comptype = 'ausziehtablarverkehrt' ++ width ++ uscore ++ depth;
        } else {
          comptype = comptype ++ width ++ uscore ++ depth;
        }
     } else if (comptype eq 'tablar') {
       comptype = comptype ++ width ++ uscore ++ depth;
     } else if (StringContains(comptype, 'blech')) {
       comptype = call blechName(comptype,type,width,depth);
     } else if (comptype eq 'tuere') {
       comptype = 'tuerelement' ++ width ++ uscore ++ height;
     } else if (comptype eq 'sperrstange') {
       comptype = comptype ++ uscore ++ length;
     } else if (comptype eq 'griff') {
       comptype = comptype ++ uscore ++ 'normal';
     } else if (comptype eq 'schubladenauszug') {
       comptype = comptype ++ width;
     } else if (comptype eq 'schublade') {
       comptype = comptype ++ uscore ++ type ++ uscore ++ 'o';
     } else if (comptype eq 'scherengelenk') {
       comptype = comptype ++ uscore ++ side;
     } else if (comptype eq 'box') {
       comptype = 'schubladenrahmen' ++ width ++ uscore ++ depth ++ uscore ++ height;
     } else if (comptype eq 'einschubtuere') {
       comptype = 'einschubtuer' ++ height;
       if (width eq '500') {
         comptype = comptype ++ uscore ++ 'b' ++ width;
       }
      } else if (comptype eq 'einschubtuergelenk') {
       comptype = comptype ++ uscore ++ side;
     }                                                                                                                                      

     return comptype;
   }

def tablschlitzBleche() {
    my schlitzBleche = List();
    my griffe = GetComponentListOfType('ct_griff_normal');
    my bleche = GetComponentListOfType('ct_standardblech');
    my bleche_ggw = GetComponentListOfType('gewichtbleche');
    my bleche = JoinList(bleche,bleche_ggw);
    my hoehe = 0; 
    my posx = 0;   
    for (my griff : griffe) {
      hoehe = PartPos(griff)['z'];
      posx = PartPos(griff)['x'];
      for (my blech : bleche) {
        if (InRange(hoehe-5,hoehe-2,PartPos(blech)['z']) and InRange(posx - 1,posx + 1,PartPos(blech)['x'])) {
          schlitzBleche = ListAdd(schlitzBleche,blech);
        }
      }
    }
    return schlitzBleche;
    }

def horizontalRohr(rohre,size) {
    my rohrliste = List();
    my horizontal = List();
    my rohr = null;
    my hoehe = 0;
    my laenge = 0;
    my maxhoehe = 99999.99;

    for (my i = 0; i lt Size(rohre); i = i + 1) {
     rohr = rohre[i];
     hoehe = PartPos(rohr)['z'];
     laenge = PartAttr(rohr,'hc_length');
     if (call horizontalPart(rohr) and laenge eq size) {
         horizontal = ListAdd(horizontal,rohr);
         if (hoehe lt maxhoehe) {
           maxhoehe = hoehe;
         }
       }
    }
    /* alle horzontale Rohre, die auf der Hoehe des untersten Rohres sind */
    rohrliste = FilterList(horizontal,'element',`my z = PartPos(element)['z']; not InRange(maxhoehe-2,maxhoehe+2,z);`);
    return rohrliste;
    }

def stossbuegeltuere(part,dimension) {
    my retval = 0; 
    my p= Parent('mainstructure');
    p= p ? Parent('mainstructure', p) : 0;
    my show= p AND IsSubTypeOf(p, 'ausziehtuertablarset') ? true : false;
    my p_name= p ?  GetTypeName(p) : '';
    my length= show ? SubStr(p_name, 12, 3)/10 : 0;
    my depth= show ? SubStr(p_name, 16, 3)/10 : 0;
    my height= show ? SubStr(p_name, 20, 3)/10 : 0;

    if (dimension eq 'posx') {
      retval = -length/2 - 1.5;
    } else if (dimension eq 'posy') {
      retval = depth/2 - 6;
    } else if (dimension eq 'posz') {
      retval = height - 14.5;
    } else if (dimension eq 'posz2') {
      retval = height - 15.5;
    } else if (dimension eq 'sizez') {
      retval = show ? 6 : 0;
    }
    return retval;
    }

def missingTablarSchlitz() {
    my conflicts = List(); 
    my gelenke = List();
    my bleche = List();
    my bleche_ggw = List();
    my vol = null;
    my volname = '';
    my blech = null;
    my volhoehe = 0;
    my gelenkhoehe = 0;
    gelenke = GetComponentListOfType('einschubtuergelenk_l');
    if (Bool(Size(gelenke))) {
      for (my gelenk : gelenke) {      
        vol = MainRoot(gelenk);
        volname = GetTypeName(vol);
        if (IsSubTypeOf(vol,'normal_volume')) {
          volhoehe = Feature(vol,'zlength');
          gelenkhoehe = PartPos(gelenk)['z'];
          bleche = FilterList(GetVolumeRefParts(vol),'element',`not IsSubTypeOf(element,'ct_standardblech');`);
          bleche_ggw = FilterList(GetVolumeRefParts(vol),'element',`not IsSubTypeOf(element,'gewichtbleche');`);
          bleche = JoinList(bleche,bleche_ggw);
          if (Bool(Size(bleche))) {
            bleche = FilterList(bleche,'element',`call vertikalBlech(element);`);
            if (Bool(Size(bleche))) {
              bleche = FilterList(bleche,'element',`my blechhoehe = PartPos(element)['z'];not InRange(gelenkhoehe - (volhoehe + 2),gelenkhoehe - (volhoehe - 2), blechhoehe);`);
              if (Bool(Size(bleche))) {
                blech = bleche[0];
              }
            }
          }  
          if (blech) {
            if (not Feature(blech,'tablschlitz')) {
              conflicts = ListAdd(conflicts,blech);
            }
          }
        }
      }
    }
    return conflicts;
    }

def checkSperrstangen() {
    my sperrstangen = List();
    my allsperrstangen = List();
    my regalstangen = List();
    my sperrstangen_temp = List();
    my sperrhalbelaenge = 0;
    my sperrhoehe = 0;
    my unten = 0;
    my oben = 0;
    my lower = 0;
    my upper = 0;
    my selectedcomponents = List();
    my sperrbleche = List();
    my sperrnachbarn = List();
    my nacbbarstangen = List();
    my sperrvolumes = List();
    my refparts = List();
    my kugeln = List();
    my possible = call separatePossible();

    if (possible[0]) {
       /* holt alle sperrstangen des gesamten Regals */
       for (my regalvol : possible[4]) {
          regalstangen = ChildrenListOfTypeDeep(regalvol, 'sperrstange');
          if (Bool(Size(regalstangen))) {
            allsperrstangen = JoinList(allsperrstangen, regalstangen);
          }
       }
       /* ueberprueft, ob sie die Unterseite der selektierten Volumen durchstossen  */
       /* ueber alle sperrstangen  */
       if (Size(allsperrstangen) gt 0) {
	       for (my sperrstange : allsperrstangen) {
	          /* 4 cm Zusatz, damit die inneren Sperrstangen das untere Blech auch durchstossen */
	          sperrhalbelaenge = Number(SubStr(GetTypeName(sperrstange),12,3)/20) + 1;
	          sperrhoehe = PartPos(sperrstange)['z'];
	          lower = Round(sperrhoehe - sperrhalbelaenge);
	          upper = Round(sperrhoehe + sperrhalbelaenge);
	          /* ueber die selektierten Volumen */
	          for (my volume : possible[3]) {
	            unten = Round(PartPos(volume)['z'] - Feature(volume,'zlength')/2); 
	            oben = Round(PartPos(volume)['z'] + Feature(volume,'zlength')/2); 
	           /* Message(lower ++ ', ' ++ upper ++ ', ' ++ hoehe); */
	            if (InRange(lower,upper,unten) or InRange(lower,upper,oben) ) {
	              sperrstangen_temp = ListAdd(sperrstangen_temp,sperrstange);
	            }
	          }
	       }
       }
       for (my volume : possible[3]) {
         refparts = GetVolumeRefParts(volume);
         kugeln = FilterList(refparts,'element', 'not IsSubTypeOf(element,`kugel`);');
         kugeln = SortByValue(kugeln, 'PartPos(element)[`z`];');
         ListSplice(kugeln, 0, 4, null);
         for (my sperrstange : sperrstangen_temp) {
           if (call inEbene(kugeln, PartPos(sperrstange))) {
             if (not InList(sperrstangen,sperrstange)) {
              sperrstangen = ListAdd(sperrstangen,sperrstange); 
            }
           }
         }
       }
    }     
    return sperrstangen;
  }

def inEbene(e, v) {
    my inside = false;
    my triangleList = List();
    ListAdd(triangleList, List(PartPos(e[0]), PartPos(e[1]), PartPos(e[2])));
    ListAdd(triangleList, List(PartPos(e[0]), PartPos(e[3]), PartPos(e[1])));
    ListAdd(triangleList, List(PartPos(e[1]), PartPos(e[2]), PartPos(e[3])));
    for (my t : triangleList) {
        if (PointInPolygon(v, t)) {
            inside = true;
            break;
        }
    }
    return inside;
		}

def setSperrstangen(mode,mount) {
    my sperrstangen = call checkSperrstangen();
    if (mode eq 'setback' and not mount ) {
      sperrstangen = FilterList(sperrstangen,'element',`not Feature(element,'mid') ne '0';`);
      sperrstangen = FilterList(sperrstangen,'element',`Feature(DockGetConnectedPart(Dock(element,'sperrstange_oben2teleskop','1')),'mid') ne '0';`);
    }
    return sperrstangen;
  }

def blechStatus(blech) {
    my state = List();
    my mounted = Feature(blech,'Mounted'); /* Mounted */
    my dock = null;
    my rohre = List();
    my rohr = null;
    my glas = null;
    my halter = null;
    my montageids = List();
    if (blech) {
       if (IsSubTypeOf(blech,'metallverkleidung') ) {
         for (my index : List(1,2,3,4)) {
           dock = Dock(blech,'blech2rohr',index);
           rohr = DockGetConnectedPart(dock);
           if (rohr) {
             rohre = ListAdd(rohre,rohr);
           }
         }
       } else if (IsSubTypeOf(blech,'glasverkleidung')) {
         glas = blech;
         for (my index : List(1,2,11,12)) {
           dock = Dock(glas,'glas2glashalter',index);
           halter = DockGetConnectedPart(dock);
           if (halter) {
             for (my index : List(1,2)) {
               dock = Dock(halter,'glashalter2rohr',index);
               rohr = DockGetConnectedPart(dock);
               if (rohr) {
                rohre = ListAdd(rohre,rohr);
               }
             }
          }
        }
      }
	    if (rohre[0]) {
	      montageids = FeatureValuesFromPartList(rohre, 'montageid');
	      state = call defineMontageId(mounted,montageids);
	    }
    }
    return state;
  }

def defineMontageId(mounted,montageids) {
	  my state = List();
	  state[0] = mounted;
    my maxlist = List();
    my max = 0;
    my count = 0;
    my maxid = '';
    my md = ''; 
	  my ids = UniqueList(montageids);
    for (my id : ids) {
      count = 0;
      for (my mid : montageids) {
        if (id eq mid) {
          count = count + 1;
        }
      }
      if (count gt max) {
           max = count;
           maxid = id; 
      }  
    }
    if (mounted) {
      /* Regal-MontageBlock Id */
	    md = StringToList(maxid,'.')[1];
	    if (md eq 0) {
	      state[0] = 'false';
	    }
	    state[2] = maxid;
	    state[3] = md;
    } else {
       /* Regal ID */
       md = StringToList(maxid,'.')[0];
       state[0] = 'false';
       state[2] = md ++ '.0';
       state[3] = '0';
    }
	  return state;
	}

def seitenLeiterState(selectedparts) {
     my state = List();
     my montageids = List();
     my montageid = '';
     my rohr = null;
     my rohre = List();
     my glas = null;
     my halter = null;
     my dock = null;
     my bleche = call seitenLeiterBleche(selectedparts);
     my blech = bleche[0];
     if (blech) {
       if (IsSubTypeOf(blech,'metallverkleidung') ) {
         for (my index : List(1,2,3,4)) {
          dock = Dock(blech,'blech2rohr',index);
          rohr = DockGetConnectedPart(dock);
            if (rohr) {
              rohre = ListAdd(rohre,rohr);
            }
          }
       } else if (IsSubTypeOf(blech,'glasverkleidung')) {
         glas = blech;
         for (my index : List(1,2,11,12)) {
          dock = Dock(glas,'glas2glashalter',index);
          halter = DockGetConnectedPart(dock);
          if (halter) {
            for (my index : List(1,2)) {
              dock = Dock(halter,'glashalter2rohr',index);
              rohr = DockGetConnectedPart(dock);
              if (rohr) {
                rohre = ListAdd(rohre,rohr);
              }
            }
          }
        }
       }
       if (rohre[0]) {
         montageids = FeatureValuesFromPartList(rohre, 'montageid');
         if (Size(montageids) gt 0) {
           montageid = montageids[0];
           state[0] = 'false';
           state[2] = StringToList(montageid,'.')[0] ++ '.0';
           state[3] = '0';
         }
       }
     }
     return state;
  }

def seitenLeiterBleche(selectedparts) {
     my bleche = List();
     bleche = FilterList(selectedparts,'element',`not IsSubTypeOf(element,'verkleidung');`);
     bleche = FilterList(bleche,'element',`Feature(element, 'Mounted');`);
     bleche = FilterList(bleche,'element',`Feature(element, 'mid') eq 0;`);
     bleche = FilterList(bleche,'element',`not HasFeature(element, 'montageid');`);
     return bleche;
  }

def setMountStateSperrstangeDetached(part) {
  my setlist = List();
  my sperrstangen = List();
  my getrennt = false;
  my gesperrt = false;
  my volumes = GetRefVolumes(part, 'mainstructure');
  my parts = List();
  my contentparts = List();
  my shelfparts = List();
  my trennlist = List();
  my sperrstangen = List();
  if (IsSubTypeOf(part,'AZT')) {
    volumes[0] = MainRoot(part);
  }
  for (my vol : volumes) {
     parts = ChildrenListOfTypeDeep(vol,'haller_shelf_component');
     contentparts = JoinList(contentparts,parts);
  }
  sperrstangen = FilterList(contentparts,'element',`not IsSubTypeOf(element,'sperrstange');`);
  gesperrt = Bool(Size(sperrstangen));
  if (gesperrt) {
    for (my vol : volumes) {
     parts = GetVolumeRefParts(vol);
     shelfparts = JoinList(shelfparts,parts);
    }

    trennlist = FilterList(shelfparts,'element',`not Feature(element,'mid') ne '0';`);
    /* trennlist = FilterList(trennlist,'element',`Feature(element,'Mounted');`); */
    getrennt = Bool(Size(trennlist));
  }

  if( gesperrt and getrennt) {

    setlist = sperrstangen;
  }
  return setlist;
  }

def scherengelenkTyp(gelenk,kind) {
	  my active = false;
	  my tuere = FindPart(gelenk,'tuerelement');
	  my height = PartAttr(tuere,'height');
	  my width = PartAttr(tuere,'width');
	  if (kind eq '30N') {
	    active = height eq '17.5';
	    } else if (kind eq '40N') {
	      active = height eq '25' or (height eq '35' and width lt 50);
	    } else if (kind eq '69N') {
	      active = height eq '39.5' or (height eq '35' and width ge 50);
	    }
	  return active;
	}

def mountingheightAZT(part) {  
    my mountingheight = 1;
    my volhoehe = 0;
    my bodenhoehe = 0;
    my teleskophoehe = PartPos(part)['z'];
    my vol = MainRoot(part);
    if (vol) {
      volhoehe = PartPos(vol)['z'];
      bodenhoehe = volhoehe - Feature(vol,'zlength')/2;
      mountingheight = Round((teleskophoehe - bodenhoehe - 1),0.5);
    }
    return NumberToString(mountingheight,0);
  }

def kettenElementAmount(part) { 
			my diag = Power(Feature('f_kettenBreite_top') * 0.1 ,2) + Power(Feature('f_kettenHoehe_top') * 0.1 ,2);
			diag = Sqrt(diag);
			my amount = Round(diag/3,1.0);
      return amount;
   }

def kettenElementDefinitions(part,count,index,mode) { 
      my retval = '';
      my laenge = Feature('f_kettenBreite_top') * 0.1;
      my hoehe = Feature('f_kettenHoehe_top') * 0.1;
      my breite = Feature('f_kettenGliedBreite_top');
      my amount = count;
      my delta = 1 / amount;
      my x = (index + 1) * delta; 
      my alpha = (Power(E,x) - Power(E,-x)); /* Ableitung */
      if (mode eq 'transx') {
         delta = laenge / amount;
         retval = (index + 1) * delta;
      } else if (mode eq 'transz') {
         retval = (Power(E,x) + Power(E,-x)) * hoehe;
      } else if (mode eq 'roty') {
         /* im Viertelkreis */
         retval = - ATan(alpha) * 2 / PI * 90;
      }
      return retval;
   }

def lonelyParts() {
    my conflicts = List(); 
    my checklist = List();
    my parent = null;
    my partlist = GetComponentListOfType('ct_haller_shelf_component');
    my checklist = FilterList(partlist,'element',`ParentOfType(element, 'mainstructure', 'volume');`);
    checklist = FilterList(checklist,'element',`IsConnectedToVolume(element,'mainstructure');`);
    checklist = FilterList(checklist,'element',`ParentOfType(element, 'mainstructure', 'sub_assembly');`);
    checklist = FilterList(checklist,'element',`FindPart(element,'nktrohr');`);
    checklist = FilterList(checklist,'element',`IsSubTypeOf(element,'co_safety_dummy') and DockGetConnectedPart(Dock(element, 'safety_2_kugel', 1));;`);
    checklist = FilterList(checklist,'element',`IsSubTypeOf(element,'co_qs_article') and DockGetConnectedPart(Dock(element, 'qs_article_2_part', 1));`);
    checklist = FilterList(checklist,'element',`DockGetConnectedPart(Dock(element,'einschubtuergelenk2einschubtuerhalter','1'));`);
    for (my element : checklist) {
      if (IsSubTypeOf(element,'tuerelement')) {
         parent = Parent('mainstructure',element);
         if (parent) {
            if (not IsSubTypeOf(parent,'tuerelementset') and not IsSubTypeOf(parent,'klapptuerset')) {
              conflicts = ListAdd(conflicts, element);
            }
         } else {
            conflicts = ListAdd(conflicts, element);
         }
      } else {
         conflicts = ListAdd(conflicts, element);
      }

    }
    return conflicts;
 }

