def tuerenDoppelteSystemtiefe() {
    my conflicts = List(); 
    my checklist = List();
    my hitvol_0 = null;
    my hitvol_1 = null;
    my partlist = GetComponentListOfType('ct_haller_shelf_component');
    my tuerelemente = FilterList(partlist,'element',`not IsSubTypeOf(element, 'tuerelement');`);
    my glastueren = FilterList(partlist,'element',`not IsSubTypeOf(element, 'glastuer');`);
    my checklist = JoinList(tuerelemente,glastueren);
    for (my tuere : tuerelemente) {
    	my hit = call invalidBlech(tuere, 'metall');
    	if (hit) {
    		conflicts = ListAdd(conflicts,tuere);
    	}
    }
    for (my tuere : glastueren) {
    	my hit = call invalidBlech(tuere, 'glas');
    	if (hit) {
    		conflicts = ListAdd(conflicts,tuere);
    	}
    }
     return conflicts;
 }

def invalidBlech(part,doortype) {
		my p1 = Vector();
		my p2 = Vector();

		if (doortype eq 'metall') {
		p1 = Vector(0,10,-PartAttr(part,'height')/2+1);
		p2 = Vector(0,10,-PartAttr(part,'height')/2-10);
		} else if (doortype eq 'glas') {
		/* Local coord. system of glastuere is different */
		p1 = Vector(0,-PartAttr(part,'height')/2+1,10);
		p2 = Vector(0,-PartAttr(part,'height')/2-10,10);
		}
		my center= GlobalPos(part,p1);
		my direction= VectorSub(GlobalPos(part,p2),center);
		/* center and direction are now in the global coordinate system */

		my info = GetIntersectionInfo('1000', Line(center,direction), 'metallverkleidung', part);
		my hit = info['part'];

		return hit;
	}

