def checkRiegelVerkuerzt(part) {
	my fixedpart = null;
	my tuerelement = DockGetConnectedPart(ConnectedDocksOfType(part, 'schlossgriff2tuer'));
	my scherengelenklist = ConnectedDocksOfType(tuerelement, 'tuer2scherengelenk');

	if (Size(scherengelenklist) eq 0){
		my tablar = DockGetConnectedPart(ConnectedDocksOfType(tuerelement, 'tuer2tablar'));
		fixedpart = DockGetConnectedPart(ConnectedDocksOfType(tablar, 'tablar2teleskop'))[0];
		my klemmhalter = DockGetConnectedPart(ConnectedDocksOfType(fixedpart, 'anything2klemmhalter')[0])[0];
		my seitenblech = DockGetConnectedPart(ConnectedDocksOfType(klemmhalter, 'klemmhalter2blech')[0])[0];
	}
	else {
		fixedpart =  DockGetConnectedPart(scherengelenklist[0]);
		my klemmhalter = DockGetConnectedPart(ConnectedDocksOfType(fixedpart, 'anything2klemmhalter')[0])[0];
		my seitenblech = DockGetConnectedPart(ConnectedDocksOfType(klemmhalter, 'klemmhalter2blech')[0])[0];
	}

	/* Determine if width is actually height or depth... */
	if(StringToList(Feature(tuerelement, 'f_anzeige_tuer_dimension'), 'x')[1] gt StringToList(call blechDimension(seitenblech), 'x')[0]){
		my seitenblech_height = StringToList(call blechDimension(seitenblech), 'x')[0]/10;
		my seitenblech_depth = StringToList(call blechDimension(seitenblech), 'x')[1]/10;		
	} else{
		my seitenblech_height = StringToList(call blechDimension(seitenblech), 'x')[1]/10;
		my seitenblech_depth = StringToList(call blechDimension(seitenblech), 'x')[0]/10;	
	}

  	my einsatzlist = GetComponentListOfType('einsatzverkleidung');
  	my glaslist = GetComponentListOfType('normalglas');
  	my einsatzundglaslist = JoinList(einsatzlist, glaslist);
  	my bibliolist = GetComponentListOfType('biblioblech');
  	my metallverkleidungslist = GetComponentListOfType('metallverkleidung');
	metallverkleidungslist = FilterList(metallverkleidungslist,'element',`IsSubTypeOf(element, 'biblio') or RelativePartRot(fixedpart, element)['x'] ne 0 or RelativePartRot(fixedpart, element)['y'] ne 0;`);
  	my elementlist = JoinList(einsatzundglaslist, bibliolist);
  	my fulllist = JoinList(metallverkleidungslist, elementlist);

	/* Find height of side for maximum z relative pos detection*/
	my klemmhalter = DockGetConnectedPart(ConnectedDocksOfType(fixedpart, 'anything2klemmhalter')[0])[0];
	my seitenblech = DockGetConnectedPart(ConnectedDocksOfType(klemmhalter, 'klemmhalter2blech')[0])[0];
	my z_max = StringToList(Feature(tuerelement, 'f_anzeige_tuer_dimension'), 'x')[1]/10;

	/* Find width of door for maximum x relative pos detection*/
	my door_width = StringToList(Feature(tuerelement, 'f_anzeige_tuer_dimension'), 'x')[0]/10;

	for (my element: fulllist){
		my rp = RelativePartPos(fixedpart, element);
		my x_check = rp['x'] ge -(3+door_width/2) and rp['x'] le -(-3+door_width/2);
		if(Size(scherengelenklist) eq 0){
			my y_check = Round(rp['y']) eq 0;
		}
		else {
			my y_check = rp['y'] ge 2 and rp['y'] le (seitenblech_depth + 5);
		}
		my z_check = rp['z'] ge (z_max-5) and rp['z'] le (z_max+5); 

		if (x_check and y_check and z_check){
			if (InList(bibliolist, element) and Round(RelativePartRot(part, element)['z']) ne 0){
				return false; /* Verkuerzter Riegel nicht bei biblio mit anderer Ausrichtung */
			}	else if (InList(einsatzlist, element)){
				return true; /* Verkuerzter Riegel bei Einsatz*/
			}	else if (InList(glaslist, element)){
				return 'Glas'; /* Verkuerzter Riegel bei Glas */
			}	else if (InList(metallverkleidungslist, element)){
				return false; /* Verkuerzter Riegel nicht bei anderen Metallelementen */
			}
		}
	}
	return true; /* Verkuerzter Riegel wenn sonst nichts gefunden */
	}

