def checkCounterTube(part) {
    my found = false; 
    my foundings = List();
    my countertube = null;
    my p1 = Vector(0,0,0);  
    my center = GlobalPos(part,p1);
    my horizontal = call horizontalPart(part);
    my line = List();
    my direction = Vector();
    my dirs = List();
    my info = List();
    my spheres = FilterList(GetComponentListOfConnectionId(ConnectionId(part)),'element',`not IsSubTypeOf(element,'kugel');`);
    /* Gibt immer zwei Suchweiten */
    my depths = call shelfDepthToCounterTube(part,horizontal,spheres);
    my foundedparts = List();
    for (my j : List(0,1)) {
      dirs = List(Vector(depths[j],0,0),Vector(-depths[j],0,0),Vector(0,0,depths[j]),Vector(0,0,-depths[j]));
      for (my dir : dirs) {
        direction = VectorSub(GlobalPos(part,dir), center);
        line = Line(center, direction);
        if (horizontal) {    
          line['origin']['y'] = line['origin']['y'] +1.5;
        } else {
          line['origin']['z'] = line['origin']['z'] +1.5;
        }
        info = GetIntersectionInfo('1000', line, 'rohr', part);
        if (not info['part']) {
          info = GetIntersectionInfo('1000', line, 'kugel_gew', part);
        }
        if (info['part']) {
          /* Damit nicht ein Rohr zweimal gefunden wird */
          if (not InList(foundedparts,info['part'])) {
             foundings[j] = true;
             foundedparts = ListAdd(foundedparts,info['part']);
           break;
           }
        }
      }
    }

    if (horizontal) {
      found = Bool(foundings[0]) or Bool(foundings[1]);
    } else {
      found = Bool(foundings[0]) and Bool(foundings[1]);
    }
    return found;
  }

