  }

def nearestSphereDist(base, line, horizontal, spheres) {
    my mindist = -1;
    if (horizontal) {
      spheres = FilterList(spheres,'element',`Round(PartPos(element)['z']) ne Round(PartPos(base)['z']);`);
    }
    if (Bool(spheres[0])) {
	    for (my s : spheres) {
	      if (s ne base) {
	        if (LinePointDistance(line, PartPos(s)) lt 0.3) {
	          my len = VectorLength(VectorSub(PartPos(s), PartPos(base)));
	          if (mindist lt 0 or len lt mindist) {
	            mindist = len;
	          }
	        }
	      }
	    }
    }
    return mindist;
  }

def shelfDepthToCounterTube(part,horizontal,spheres) {
    my depths = List();
    my mindist = 0;
    my p1 = Vector(0,0,0);
    my kpos = Vector();
    my dpos = Vector();
    my infos = List();
    my centers = List();
    my depth = 76;
    my dirs = List(Vector(depth,0,0),Vector(-depth,0,0),Vector(0,0,depth),Vector(0,0,-depth));
    my line = List();
    my direction = Vector();
    my info = List();   
    my kugeln = List();
    kugeln[0] = DockGetConnectedPart(Dock(part,'rohr2kugel',1));
    kugeln[1] = DockGetConnectedPart(Dock(part,'rohr2kugel',2));
    if (not kugeln[1]){
      kugeln[1] = DockGetConnectedPart(Dock(part,'rohr2gewinde_90',2));
      if (not kugeln[1]){
        kugeln[1] = DockGetConnectedPart(Dock(part,'rohr2gewinde_180',2));
      }
    }
    if (kugeln[0] and kugeln[1]) {
      centers[0] = GlobalPos(kugeln[0], p1);
      centers[1] = GlobalPos(kugeln[1], p1);
      for (my i : List(0,1)) {
        for (my dir : dirs) {
          kpos = LocalPos(part, PartPos(kugeln[i]));
          dpos = VectorAdd(kpos, dir);
          direction = VectorSub(GlobalPos(part, dpos), GlobalPos(part, kpos));
          line = Line(centers[i], direction);
          mindist = call nearestSphereDist(kugeln[i], line, horizontal, spheres);
          ListAdd(infos, mindist);
        }
      }
      /* Wenn keine Kugel dann keine Distanz */
      infos = FilterList(infos,'element',`element lt 2;`);
      /* Bei Vertikal-Rohren, wenn mehrere unterschiedliche Distanzen */
      if (Size(infos) gt 2 and ListMax(infos) ne ListMin(infos)) {
        infos = UniqueList(infos);
      }
      /* Groesste Distanz zuletzt */
      infos = SortByValue(infos, 'element;');
      /* die zwei Suchdistanzen bei Verikalrohr */
      if (Size(infos) ge 2 and not horizontal) {
        depths[1] = ListRemoveLast(infos) + 1;
        depths[0] = ListRemoveLast(infos) + 1;
      }
      /* die zwei Suchdistanzen bei Horizontalrohr, es wird nur mit der groessten Distanz gesucht */
      if (horizontal) {
        depths[0] = ListRemoveLast(infos) + 1;
        depths[1] = depths[0] + 0.1; /* damit es wirklich zwei Werte hat in der Liste der Suchdistanzen */
      }
    }
    return depths;
  }

