def isEndRohr(rohr,mode) {
    my ende = false;
    my posz = 0;
    my rohre = List();
    my kugeln = List();
    my rohrdocks = List();
    my kugeldocks = ConnectedDocksOfType(rohr,'rohr2kugel');
    for (my kugeldock : kugeldocks) {
       kugeln = ListAdd(kugeln,DockGetConnectedPart(kugeldock));
    }  
    /* Message(kugeln); */
    for (my kugel : kugeln) {
      rohrdocks = ConnectedDocksOfType(kugel,'kugel2rohr');
      posz = Round(PartPos(kugel)['z']);
      rohre = List();
      for (my rohrdock : rohrdocks) {
        rohre = ListAdd(rohre,DockGetConnectedPart(rohrdock));
      }

      if (mode eq 'horizontal') {
         rohre = FilterList(rohre,'element',`not call horizontalPart(element);`);
        /* rohre = FilterList(rohre,'element',`Round(PartPos(element)['z']) eq posz;`); */
        /* Message(rohre); */
        if (Size(rohre) eq 2) {
          ende = true;
          break;
        }
      } else if (mode eq 'vertikal') {
        rohre = FilterList(rohre,'element',`call horizontalPart(element);`);
        /* Message(rohre); */
        if (Size(rohre) eq 1) {
          ende = true;
          break;
        }
      }
    }
  return ende;
  }

def validLeiterTrennung(selectedparts,mode) {
    my valid = false;
    my rohre = List();
    my parts = List();
    my posz = 0;
    my maxposz = 0;
    my maxposzrohr = null;
    my cam = Vector();
    my camdir = Vector();
    my volumes = FilterList(selectedparts,'element',`GetTypeName(element) ne 'normal_volume';`);

    if (volumes[0]) {
      for (my vol : volumes) {
        parts = JoinList(parts,GetVolumeRefParts(vol));
      }
      rohre = FilterList(parts,'element',`not IsSubTypeOf(element,'rohr');`);
      rohre = FilterList(rohre,'element',`PartAttr(element, 'hc_length') gt 175;`);
      if (rohre[0]) {
        if (mode eq 'horizontal') {
          cam = ViewerInfo('1000', 'camera')['camera'];
          camdir = VectorSub(cam['lookat'], cam['eyep']);
          camdir['z'] = 0;
          rohre = FilterList(rohre,'element',`not call horizontalPart(element);`);
          rohre = FilterList(rohre,'element',`call inViewDirection(element,camdir);`);
        } else if (mode eq 'vertikal') {
          rohre = FilterList(rohre,'element',`call horizontalPart(element);`);
        }

        if (Size(rohre) ge 2) {
          for (my rohr : rohre) {
             posz = PartPos(rohr)['z'];
             if (posz gt maxposz) {
               maxposz = posz;
               maxposzrohr = rohr;
             }
           }
          valid = call isEndRohr(maxposzrohr,mode);
        }
      }  
    }
    return valid;
  }

def validSchlitzRohre(selectedparts,mode) {
  my rohre = List();
  my parts = List();
  my cam = Vector();
  my camdir = Vector();
  my volumes = FilterList(selectedparts,'element',`not GetTypeName(element) eq 'normal_volume';`);
  if (volumes[0]) {
   for (my vol : volumes) {
     parts = JoinList(parts,GetVolumeRefParts(vol));
   }
   rohre = FilterList(parts,'element',`not IsSubTypeOf(element,'rohr');`);
   rohre = FilterList(rohre,'element',`not PropertyActive(element, 'schlitzrohr');`);
   if (rohre[0]) {
     if (mode eq 'normal') {
       rohre = FilterList(rohre,'element',`not Feature(element, 'Schlitz');`);
       /* rohre = FilterList(rohre,'element',`EndsWith(Feature(element, 'montageid'),'.0');`); */
     } else if (mode eq 'vertikal') {
       rohre = FilterList(rohre,'element',`call horizontalPart(element);`);
     } else if (mode eq 'horizontal') {
       cam = ViewerInfo('1000', 'camera')['camera'];
		   camdir = VectorSub(cam['lookat'], cam['eyep']);
		   camdir['z'] = 0;
       rohre = FilterList(rohre,'element',`not call horizontalPart(element);`);
       rohre = FilterList(rohre,'element',`call inViewDirection(element,camdir);`);
     }
   }
  }
  return rohre;
}

def validLochRohre(selectedparts,mode) {
  my rohre = List();
  my parts = List();
  my cam = Vector();
  my camdir = Vector();
  my volumes = FilterList(selectedparts,'element',`not GetTypeName(element) eq 'normal_volume';`);
  if (volumes[0]) {
   for (my vol : volumes) {
     parts = JoinList(parts,GetVolumeRefParts(vol));
   }
   rohre = FilterList(parts,'element',`not IsSubTypeOf(element,'rohr');`);
   rohre = FilterList(rohre,'element',`not HasFeature(element, 'Loch');`);
   /* Rohre die keine Glasverkleidung haben rausfiltern */
   rohre = FilterList(rohre,'element',`ConnectedDockCount(element, 'rohr2glashalter') eq 0;`);
   my rohreMitHorizontalBlech = call rohreOhneBohrung(parts);

   for(my removerow : rohreMitHorizontalBlech){
   	 if(InList(rohre, removerow)){
   		ListRemove(rohre, removerow);
   	 }
   }
  }
  return rohre;
}

def rohreOhneBohrung(rohre){

		my rohrmitblech = List();
		for( my mypart : rohre){
			my parttypename = GetPartTypeName(GetPartType(mypart));
			if(parttypename eq 'rohr750'){
				my rohrdocks = ConnectedDocksOfType(mypart, 'rohr2blech');
				for(my rohrdock : rohrdocks){
					my partnerdock = DockGetConnectedDock(rohrdock);
					my partnerpart = DockGetPart(partnerdock);
					if(not(call vertikalBlech(partnerpart))){
						rohrmitblech = ListAdd(rohrmitblech, mypart);
					}
				}
			}
		};
		return rohrmitblech;


	};

def fraesrohrVerkleidungen(connectionid,selectedcomponents) {
	  my fraesrohrpanel = List();
	  my verkleidungen = FilterList(selectedcomponents,'element',`not IsSubTypeOf(element,'verkleidung');`);
	  my regalverkleidung = GetComponentListOfConnectionId(connectionid);
	  my regalverkleidungen = FilterList(regalverkleidung,'element',`not IsSubTypeOf(element,'verkleidung');`);
	  for (my panel : verkleidungen ) {
	    if (InList(regalverkleidungen,panel)) {
	      fraesrohrpanel = ListAdd(fraesrohrpanel,panel);
	    }
	  }
	  return fraesrohrpanel;
	}

def inViewDirection(rohr,camdir) {
    my viewdirection = false;
    my d1 = Dock(rohr, 'rohr2kugel', 1);
    my d2 = Dock(rohr, 'rohr2kugel', 2);
    my v1 = GlobalPos(rohr, DockPos(d1));
    my v2 = GlobalPos(rohr, DockPos(d2));
    my rohrdir = VectorSub(v1,v2);
    rohrdir['z'] = 0;
    my angle = VectorAngle(rohrdir, camdir) * 180 / PI; 
    if (angle gt 90) {
     angle = (180 - angle);
    }
    if (angle le 45) {
      /* bei genau 45 Grad liegen alle Rohre in Blickrichtung und werden somit nicht geschlitzt */
      viewdirection = true;
    }
    return viewdirection;
  }

def garderobestangeCollision(part) {
    my sizeZ = 0;
    my blech = null;
    for (my index : List('1','2','3','4')) {
      blech = FindPart(part,'anything2klemmhalter',index,'klemmhalter2blech');
      if (blech) {
        if (not call vertikalBlech(blech)) {
          /* somit kann ein AZT oberhalb einer Gst. nur noch ab Position 4 eingebaut werden */
          sizeZ = 3;
        }
        break;
      }
    }
  return sizeZ;
  }

def printzonevolumelength(mypart) {
			my clause = false;
			my groupid = USMPartGroupId(mypart);
			my volumes = call groupIdVolumeList(groupid);
			my volposz = List();
			for (my volume : volumes) {
				ListAdd(volposz,Round(PartPos(volume)['z']));
			}
			volposz = UniqueList(volposz);
			for (my pos : volposz) {
				my x_length = 0;
				my y_length = 0;
				my vol_sum = FilterList(volumes,'volume',`Round(PartPos(volume)['z']) NE pos;`);
				for (my i : vol_sum) {
					x_length = x_length + Feature(i,'xlength');
					y_length = y_length + Feature(i,'ylength');
				}
				if (x_length GE 300 OR y_length GE 300) {
					clause = true;
					break;
				}
			}
			return clause;
		}

def sperrstangeMitSchraegtablar() {

	my conflicts = List();

  my allComponents = GetComponentList(); 
  my schraegtablare = List();
  my sperrstangen = List(); 
  /* klemmzunge_r als representant des schraegtablars */
	schraegtablare = FilterList(allComponents, 'element', `not BeginsWith(GetTypeName(element), 'klemmzunge_r');`);
	if(Size(schraegtablare) gt 0){
		sperrstangen = FilterList(allComponents, 'element', `not BeginsWith(GetTypeName(element), 'sperrstange');`);
		if(Size(sperrstangen) gt 0){
			for(my schraegtablar : schraegtablare) {
				for(my sperrstange : sperrstangen) {
					if(ConnectionId(schraegtablar) eq ConnectionId(sperrstange)){
						if(call schraegtablarPosition(schraegtablar, sperrstange)){
							conflicts = ListAdd(conflicts, schraegtablar);
							break;
						}
					}
				}	
			}	
		}		 			 			 	
	} 
	return conflicts;
}

def schraegtablarPosition(schraegtablar, sperrstange) {

		my conflict = false;

		my width = PartAttr(schraegtablar,'width');
		my length = PartAttr(sperrstange,'length');
		my distx = width/20;
		my disty = 7; /* distanz klemmzunge_r */		
		my distz = length/20;
		my klemmPosZ = PartPos(schraegtablar)['z'];
		my sperrstangePosZ = PartPos(sperrstange)['z'];	
		my depth = 0;	
		my relpos = 0;
		my xdirection = false;
		my ydirection = false;
		my zdirection = false;

		relpos = RelativePartPos(schraegtablar,sperrstange);
		xdirection = InRange(distx-2,distx+1,Abs(relpos['x']));			
		ydirection = InRange(disty-1,disty+1,Abs(relpos['y']));
		zdirection = InRange(sperrstangePosZ-distz,sperrstangePosZ+distz,klemmPosZ);


		if(xdirection and ydirection and zdirection) {
			conflict = true;	
		}			
		return conflict;
  }

def notIncludedInSafety(grouplist){
    my conflicts = List();
    my groupids = List();
    my volumes = List();
    for ( my groupid : grouplist ) {
      my group_parts = call groupIdPartList(groupid);
      my dim = call groupIdDimemsions(group_parts,'both');
      my height = dim[0];
      my width = dim[1]; /* kurze Seite */
      my depth = dim[2]; /* lange Seite */
      my schubladen = FilterList(group_parts,'element',`not IsSubTypeOf(element,'schublade');`);
      my schublade = schubladen[0];
      if (schublade) {
        my dim1 = width eq 395 and depth eq 500 and height lt 745;
      /* wdith wird zu depth, da breiter als tiefe */
      	my dim2 = width eq 500 and depth eq 750 and height le 789;
        if (dim1 or dim2) {
          if (Size(FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'co_gewichtplatte'));`)) eq 0) {
	          my volume = MainRoot(schublade);
	          my vols = call getVolumesInColumn(volume);
	          volume = Size(vols) gt 1 ? vols[Size(vols)-1] : volume; 
	          ListAdd(volumes,volume);
	          groupids = ListAdd(groupids,groupid);
          };
        }
      }
    }
    conflicts[0] = volumes;
    conflicts[1] = groupids;
  return conflicts;

  }

def rollenToHeight(){
    my invalid_rollen = List();
    my grouplist = call partGroupIdList('usm_haller');
    for ( my groupid : grouplist ) {
      my group_parts = call groupIdPartList(groupid);
      my rollen = FilterList(group_parts, 'row', `not IsSubTypeOf(row, 'rollen');`);
      my dimensions = call groupIdDimemsions(group_parts ,'rolle');
      if (dimensions[1] gt 0) {
        if((dimensions[0]/dimensions[1] gt 4) and rollen[1]){
          /*return a random wheel of the group to attach the height error to */
          invalid_rollen = ListAdd(invalid_rollen,rollen[1]);
        }
      }
    }
    return invalid_rollen;
  }

