def checkKabelausschnittPosition(part) {
		my positionText = 'Pos.';
		my ausschnittdock = ConnectedDocksOfType(part, 'ausschnitt2blech')[0];
		my blech = DockGetConnectedPart(ausschnittdock);
		my pos = null;
		if (RelativePartPos(blech, part)['x'] GT 0.01) {
			RelativePartPos(blech, part)['y'] GT 0.01 ? pos = '7' : (RelativePartPos(blech, part)['y'] LT -0.01 ? pos = '1' : pos = '4');
		} else if (RelativePartPos(blech, part)['x'] LT -0.01) {
				RelativePartPos(blech, part)['y'] GT 0.01 ? pos = '9' : (RelativePartPos(blech, part)['y'] LT -0.01 ? pos = '3' : pos = '6');
		} else {
			RelativePartPos(blech, part)['y'] GT 0.01 ? pos = '8' : (RelativePartPos(blech, part)['y'] LT -0.01 ? pos = '2' : pos = '5');
		}
		return 'Pos.' ++pos;
	}

def old_checkKabelausschnittPosition(part) {

    my positionText = 'Pos.';
    my ausschnittdock = ConnectedDocksOfType(part, 'ausschnitt2blech');

    if (Size(ausschnittdock) gt 0){
      my actBlechdock = DockGetConnectedDock(ausschnittdock[0]);
      my actIndex = DockGetIndex(actBlechdock);
      my blech = DockGetConnectedPart(ausschnittdock[0]);
      my blechdocks = DocksOfType(blech, 'blech2ausschnitt');
      my localpoint = Vector(0,0,0);
      my sortedBlechDocks = List();
      my sortedIndex = 1;

      for(my sortedBlechDock : IndexList(Size(blechdocks))){
        for(my blechdock : blechdocks){
          my index = DockGetIndex(blechdock);
          if(index eq sortedIndex){
            sortedBlechDocks = ListAdd(sortedBlechDocks, blechdock);
            sortedIndex = sortedIndex + 1;
            break;
          }
        }  
      }
      /* Message(GetTypeName(blech) ++ ', ' ++ DockCount(blech, 'blech2ausschnitt')); */
      if (DockCount(blech, 'blech2ausschnitt') eq 9){
        if (call vertikalBlech(blech)){ 
          /*Fall 7 8 9 gleiches z und z von 1 höher als z von 7*/ 
          if (call checkGlobalDockPosZ(sortedBlechDocks[6], sortedBlechDocks[7], 'eq')){
            if (call checkGlobalDockPosZ(sortedBlechDocks[7], sortedBlechDocks[8], 'eq')){
              if (call checkGlobalDockPosZ(sortedBlechDocks[0], sortedBlechDocks[6], 'gt')){
                positionText = call checkCase(actIndex, '9a');
              }
            }
          }
          /*Fall 1 4 7 gleiches z und z von 3 höher als z von 1*/
          if (call checkGlobalDockPosZ(sortedBlechDocks[0], sortedBlechDocks[3], 'eq')){
            if (call checkGlobalDockPosZ(sortedBlechDocks[3], sortedBlechDocks[6], 'eq')){
              if (call checkGlobalDockPosZ(sortedBlechDocks[2], sortedBlechDocks[0], 'gt')){
                positionText = call checkCase(actIndex, '9b');
              }
            }
          }         
          /*Fall 3 2 1 gleiches z und z von 9 höher als z von 3*/
          if (call checkGlobalDockPosZ(sortedBlechDocks[2], sortedBlechDocks[1], 'eq')){
            if (call checkGlobalDockPosZ(sortedBlechDocks[1], sortedBlechDocks[0], 'eq')){
              if (call checkGlobalDockPosZ(sortedBlechDocks[8], sortedBlechDocks[2], 'gt')){
                positionText = call checkCase(actIndex, '9c');            
              }
            }
          }           
          /*Fall 9 6 3 gleiches z und z von 7 höher als z von 9*/
          if (call checkGlobalDockPosZ(sortedBlechDocks[8], sortedBlechDocks[5], 'eq')){
            if (call checkGlobalDockPosZ(sortedBlechDocks[5], sortedBlechDocks[2], 'eq')){
              if (call checkGlobalDockPosZ(sortedBlechDocks[6], sortedBlechDocks[8], 'gt')){
                positionText = call checkCase(actIndex, '9d');
              }
            }
          }
        }
        else {
          positionText = call checkCase(actIndex, '9a');
        }
      }        
      else if(DockCount(blech, 'blech2ausschnitt') eq 6) {
        my width = PartAttr(blech,'width');
        my length = PartAttr(blech,'length');
        if(InRange(100,175,width) and InRange(250,750,length) or InRange(250,750,width) and InRange(100,175,length)){           positionText = call checkCase(actIndex, '3b3c');
          /* Message(GetTypeName(blech) ++ ', ' ++ actIndex ++ ', ' ++ positionText); */
          positionText = call checkCase(actIndex, '3b3c');
        } else {
          positionText = positionText ++ actIndex;
        }  
      }
      else if(DockCount(blech, 'blech2ausschnitt') eq 3) {
        my width = PartAttr(blech,'width');
        my length = PartAttr(blech,'length');
        if(InRange(100,175,width) and InRange(250,750,length) or InRange(250,750,width) and InRange(100,175,length)){ 
          positionText = call checkCase(actIndex, '3b3b');
        }
      }
    }         
    return positionText;
}

def checkCase(actIndex, case) {

  	my text = ' ';
  	my newPosition = ' ';
  	my mapping = call createMappingPosition(actIndex, case);

  	newPosition = mapping['index',actIndex]['pos']; 
 		text = 'Pos.' ++ newPosition ++ ':';

    return text;
}

def checkGlobalDockPosZ(dock1, dock2, mode) {

  	my result = false;
    my localpoint = Vector(0,0,0);

    if (mode eq 'eq'){
    	result = Round(GlobalDockPos(dock1, localpoint)['z']) eq Round(GlobalDockPos(dock2, localpoint)['z']);
    }
    else if (mode eq 'gt'){
    	result = Round(GlobalDockPos(dock1, localpoint)['z']) gt Round(GlobalDockPos(dock2, localpoint)['z']);
    }

  	return result;  	
}

def checkConnectedKabelausschnittPosition(part) {
    my resultString = '';
    my kabelausschnittPosList = List();
    my kabelausschnittSortedPosList = List();
    my sortedList = List();
    my sortedIndex = 1;
    my feature = '';
    my pos = '';

    my kabelausschnittList = ConnectedDocksOfType(part, 'blech2ausschnitt');

    if (Size(kabelausschnittList) gt 0){
      for(my kabelausschnitt : kabelausschnittList){
        my kabelausschnittPart = DockGetConnectedPart(kabelausschnitt);
        feature = Feature(kabelausschnittPart, 'f_posNr');      
        pos = SubStr(feature, 4, 1);
        kabelausschnittPosList = ListAdd(kabelausschnittPosList, pos);
      }
      for(my kabelausschnittSortedPos : IndexList(9)){
        for(my kabelausschnittPos : kabelausschnittPosList){
          my index = kabelausschnittPos;
          if(index eq sortedIndex){
            kabelausschnittSortedPosList = ListAdd(kabelausschnittSortedPosList, kabelausschnittPos);
            break;
          }
        }
        sortedIndex = sortedIndex + 1;  
      }
      resultString = ListToString(kabelausschnittSortedPosList, ',');
    }   
    return resultString;
  }

def getBlechausschnitt(selectedparts) {

	my kabelausschnittList = List();
	my list = selectedparts;
	my blechList = List();
	my tablarList = List();
	my metallList = List();
	my docks = List();			    																											      
	blechList = FilterList(list,'element',`not IsSubTypeOf(element,'metalltablar');`);
	tablarList = FilterList(list,'element',`not IsSubTypeOf(element,'ausziehtablar');`);
	metallList = FilterList(list,'element',`not IsSubTypeOf(element,'metallverkleidung');`);
	list = JoinList(blechList, tablarList);
	list = JoinList(list, metallList);
	for(my part : list){
		docks = ConnectedDocksOfType(part,'blech2ausschnitt');
   		for(my dock : docks){
       	kabelausschnittList = ListAdd(kabelausschnittList, DockGetConnectedPart(dock));      
      }
	}
	return kabelausschnittList;  	
}

def checkTeleskopauszugsPosition() {

  my conflicts = List(); 
  my noconflicts = List();
  my senkrecht = false; 
  my allComponentList = GetComponentList();
  my allTeleskopList = List();
  my teleskopList = List();
  my relrotationz = 0;
  my partposztele = 0;
  my partposzmypart = 0;
  my distz = 0;
  my relposy = 0; 
  my relposz = 0;
  my relpos = Vector();
  my relposx = Vector();
  my relposy = Vector();

  allTeleskopList = FilterList(allComponentList,'element',`not IsSubTypeOf(element,'teleskopauszug_l');`);
  for (my mypart : allTeleskopList){
    my length = PartAttr(mypart,'length');
    my dist = length/20;
    if ( not InList(conflicts,mypart)) {   
      for (my teleskop : allTeleskopList){
        my teleskopLength = PartAttr(teleskop,'length');
        my teleskopDist = teleskopLength/20;
        relrotationz = Round(RelativePartRot(mypart, teleskop)['z']);
        if (Abs(relrotationz) eq '90'){
          partposztele = Round(PartPos(teleskop)['z']);
          partposzmypart = Round(PartPos(mypart)['z']);
          distz = Abs(partposztele - partposzmypart);
          if (InRange(0,3,distz)){
            relpos = RelativePartPos(mypart, teleskop);
            relposx = Abs(relpos['x']);
            relposy = Abs(relpos['y']);

			my offset = 0.48;
            if (teleskopLength eq length ) {
              /* +/- 0.25 -> no conflict in case of 17838 */
	            if (InRange(dist - offset, dist + offset, relposy) and InRange(dist - offset, dist + offset, relposx)){
	               if (not InList(conflicts,teleskop)) {
	                conflicts = ListAdd(conflicts, teleskop);
	              }
	            }
            } else {
              /* +/- 0.25 -> no conflict in case of 17838 */
	            if (InRange(dist - offset, dist + offset, relposy) and InRange(teleskopDist - offset, teleskopDist + offset, relposx)){
	              if (not InList(conflicts,teleskop)) {
	                conflicts = ListAdd(conflicts, teleskop);
	              }
            	}
          	}
          }
      	} 
      }
  	}
  	GetCollisions(GetComponentListOfType('stdklemmhalter'), GetComponentList());
	my collisions = GetCollisions(GetComponentListOfType('stdklemmhalter'), GetComponentList());
	if (Size(collisions) gt 0) {
  		for (my col: collisions) {
  			if (GetTypeName(col['part1']) eq 'stdklemmhalter' and IsSubTypeOf(col['part2'], 'AZT')) {
  				not InList(conflicts, col['part2']) ? ListAdd(conflicts, col['part2']) : null;
  			}
  			if (GetTypeName(col['part2']) eq 'stdklemmhalter' and IsSubTypeOf(col['part1'], 'AZT')) {
  				not InList(conflicts, col['part1']) ? ListAdd(conflicts, col['part1']) : null;
  			}
  		};
  	};

  }
  return conflicts; 
}

def collisionSchubladeSperrstange() {
		my conflicts = List();
		my uuidlist = List();
		my partlist1 = GetComponentListOfType('schubladenauszug');

		if (Size(partlist1) gt 0) {
			my partlist2 = GetComponentListOfType('sperrstange');
			my collisiongroups = List('AZSperre');
			my collisions = GetCollisions(partlist1, partlist2, collisiongroups);

			for (my i : IndexList(Size(collisions))) {
			  my auszug = collisions[i]['part1'];
			  my uuid = PartUuid(auszug);
			  /* Because there are 2 conflicts normaly by a schubladenauszug */
			  if (not InList(uuidlist, uuid)) {
			     conflicts = ListAdd(conflicts,auszug);
			     uuidlist = ListAdd(uuidlist,uuid);
			  }
			}
		}

		return conflicts;
		}

def partIsRohrWithDirection(rohr, horizontal) {
	  if (IsSubTypeOf(rohr, 'rohr')) {
	    return Feature(rohr,'f_horizontal') eq horizontal;
	  }
	  return false;
	}

def montageEinzelrohr(part) {
    my einzel = false;
    my parts = GetComponentListOfConnectionId(ConnectionId(part));
    my hor = call horizontalPart(part);
    my rohre = FilterList(parts,'element',`not (call partIsRohrWithDirection(element, hor));`);
	  if (hor) {
	    einzel = not Bool(call visaviRohr(part,rohre));
	  } else {
	     einzel = not Bool(call visaviRohrVertikal(part,rohre));
	  }
    return einzel;
   }

def beschlagsMaterialGlasTuere(part) {
    my material = 'CO';
    my beschlag  = DockGetConnectedPart(Dock(part,'glas2scharnier_vorne_oben',2));
    if (beschlag) {
      material = Feature(beschlag,'Beschlaegematerial');
    }
    return material;
    }

		def getPartsOfSupertype(parts, supertype){
		  my ret = List();
		  for(my singlepart: parts){
		    if(IsSubTypeOf(singlepart,supertype)){
		      ListAdd(ret, singlepart);
		    }
		  }
		  return ret;
}

def vertikalVerkleidung(part) { 
     my active = false;
     my rot = PartRot(part);
     my rotx = Abs(rot['x']);
     my roty = Abs(rot['y']); 
     my rotz = Abs(rot['z']); 
     my active_xz = Bool(rotx) and Bool(rotz);
     active = (Bool(rotx) or Bool(roty)) and not active_xz;
     return active;
  }

