def rohrDoppelLoch(part) {
	  my doppelloch = 'false';
	  my connections = List();
	  my zpos = 0;
	  my zlist = List();
	  my zqlist = List();
	  my localpoint = Vector(0,0,0);
	  /* Feature Loch durch C++ vergeben */
	  if (Feature(part,'Loch')) {
	    connections = ConnectedDocksOfType(part,'rohr2blech');
	    if (Size(connections) ge 2) {
		    for (my connection : connections) {
		      zpos = Round(GlobalDockPos(connection,localpoint)['z'],0.1);
		      zlist = ListAdd(zlist, zpos);
		    }
		    zqlist = UniqueList(zlist);
		    /* Message(Size(zlist) ++ ', ' ++ Size(zqlist)); */
		    if (Size(zqlist) lt Size(zlist)) {
		      doppelloch = 'true';
		    }
	    }
	  }
	  return doppelloch;
	}

