def filterSchublade(oldlist,newlist) {
    my changelist = List();
    my newpartlist = List();
    my newschloss = null;
    my newschlosslist = List();
    my poslist = List();
    my calclist = List();
    my newcalclist = List();
    for (my i : IndexList(Size(oldlist))) {
      poslist[i] = PartPos(oldlist[i]);
    }
    for (my new : newlist) {
      for (my j : IndexList(Size(poslist))) {
        if (poslist[j] eq PartPos(new)) {
           newpartlist = ListAdd(newpartlist,new);
           newschloss = FindPart(new,'schublade2schloss','1');
           if (newschloss) {
              newschlosslist = ListAdd(newschlosslist,newschloss);
           }
        }
      }
    }

    changelist[0] = newpartlist;
    changelist[1] = newschlosslist;

    return changelist;
    }

def findStuetzprofile(selectedcomponents) {
		my plist = selectedcomponents;
		my partwithdock = '';
		my parts = List();

		for (my p : plist){
			my partwithdock = ConnectedDocksOfType(p, 'blech2centralmount');
			my partwithdock_duo = ConnectedDocksOfType(p, 'blech2centralmount_duo');
			my partwithdock_mountquer = ConnectedDocksOfType(p, 'blech2centralmountquer');

			if (Size(partwithdock) gt 0){
				for (my pa : partwithdock){
					ListAdd(parts, DockGetConnectedPart(pa));
					}
				}	
			else if (Size(partwithdock_duo) gt 0){
				for (my pad : partwithdock_duo){
					ListAdd(parts, DockGetConnectedPart(pad));
					}
				}

			else if (Size(partwithdock_mountquer) gt 0){
				for (my pam : partwithdock_mountquer){
					ListAdd(parts, DockGetConnectedPart(pam));
					}
				}
			}
			parts;
				}

def countStuetzprofil(part,mode) {
		my count = 1;
		if ( EndsWith(mode,'Artikel')) {
	     part = ChildWithId(part,'10');
	    }
		my bleche = call connectedPartsByDockType(part, 'rohr2blech');
		for (my blech : bleche) {
			my connectedparts = call connectedPartsByDockType(blech, 'dt_blech2central');
			my stuetzprofile = FilterList(connectedparts,'element',`not IsSubTypeOf(element,'stuetzprofil');`);
			if (Size(stuetzprofile) gt 1) {
				count = 2;
				break;
			}
		}
		return count;
	}

def togetherAssembled(selectedcomponents) {
		  my montage_id = '';
		  my max = 0;
		  my count = 0;
		  my moebel_id = Feature(selectedcomponents[0],'montageid');
		  moebel_id = SubStr(moebel_id,0,1); /* get the Mobel-Id used in the montageid */
		  my montageids = FeatureValuesFromPartList(selectedcomponents, 'montageid');
		  /* Filtered out the unmounted parts (inside the separated range) */
		  montageids = FilterList(montageids,'element',`element eq (moebel_id ++ '.0');`);
		  my ids = UniqueList(montageids);
		  ids = Sort(ids,`StrAlphabeticalCompare(element1,element2);`);
		  /* lowest montageid that is mostly used inside the selected tubes */
		  for (my id : ids) {
		    count = 0;
		    for (my montageid : montageids) {
		       if (id eq montageid) {
		        count = count + 1;
		       }
		    }
		    if (count gt max) {
		      max = count;
		      montage_id = id;
		    }  
		  }
		  return montage_id;
		}

		def getVolumeMountingInformation(volume){
      my state = List();
      my list = List();
      my rohrliste = List();
      my getrenntliste = List();
      my separated = false;
      my unmountedlist = List();
      my unmounted = false;
      if (volume) {
        list = GetVolumeRefParts(volume);
        rohrliste = FilterList(list,'element',`not IsSubTypeOf(element,'rohr');`);
        getrenntliste = FilterList(rohrliste,'element',`Feature(element,'mid') ne 0;`);
        separated = Bool(Size(getrenntliste));
        if (not separated) {
          /* Not separated but unmounted */ 
           unmountedlist = FilterList(rohrliste,'element',`Feature(element,'Mounted');`);
           unmounted = Bool(Size(unmountedlist) ge 4);
        }
      }
      if (separated) {
        state[0] = 'false';
        state[1] = Feature(getrenntliste[0],'montageid');
        state[2] = Feature(getrenntliste[0],'mid'); 
      } else if (unmounted) {
        state[0] = 'false';
        state[1] = Feature(unmountedlist[0],'montageid');
        state[2] = Feature(unmountedlist[0],'mid'); 
       } else {
        state[0] = 'true';
        state[1] = Feature(rohrliste[0],'montageid');
        state[2] = Feature(rohrliste[0],'mid'); 
      }  
      state;
    }

