def getQSArticle(partlist) {
	my result = List();
	if (Size(partlist) gt 0) {
		my articles = GetComponentListOfType('co_qs_article');
		for (my ar: articles) {
			my cpart = DockGetConnectedPart(Dock(ar, 'qs_article_2_part', 1));
			if (cpart and InList(partlist, cpart) or ConnectionId(cpart) eq ConnectionId(partlist[0])) {
				result = List(ar);
				break;
			};
		};
	} 

	return result[0];
};

def hasQSArticle(partlist) {
	return Bool(call getQSArticle(partlist));
};

def globalColorList() {
	return call globalColorList(GetComponentList(), false, true);
};
def globalColorList(ctlist, volumesonly, unique) {

	my filterstr = ``;
	if (volumesonly) {
		filterstr = `not (IsSubTypeOf(e, 'metallverkleidung') and not IsSubTypeOf(e, 'kugel') and not IsSubTypeOf(e, 'rohr') and not IsSubTypeOf(e, 'bodenelement') and (PropertyActive(e, 'metallverkleidungsFarbe_lokal') or PropertyActive(e, 'schalentypmaterialfarbig')));`;
	} else {
		filterstr = `not (not IsSubTypeOf(e, 'kugel') and not IsSubTypeOf(e, 'rohr') and not IsSubTypeOf(e, 'bodenelement') and (PropertyActive(e, 'metallverkleidungsFarbe_lokal') or PropertyActive(e, 'schalentypmaterialfarbig')));`;
	};
	my filteredCTList = FilterList(ctlist, 'e', filterstr);
	my colors = FeatureValuesFromPartList(filteredCTList, 'Metallfarbe');
	my schalen_filter_str = `not (not PropertyActive(e, 'schalentypmaterialfarbig') and PropertyActive(e, 'schalentypmaterial'));`;
	my schalen_filtered_ct_list = FilterList(ctlist, 'e', schalen_filter_str);
	ListExtend(colors, FeatureValuesFromPartList(filteredCTList, 'Schalentypmaterialfarbig'));
	ListExtend(colors, FeatureValuesFromPartList(schalen_filtered_ct_list, 'Schalentypmaterial'));

	if (Size(filteredCTList) eq 0) {
		colors = Size(GetComponentListOfType('glashalter_std')) ? List('80') : colors;
	};	

	colors = FilterList(colors, 'c', `c eq '';`);
	if (unique) {
	 return UniqueList(colors);
	} else {
		return colors;
	};
} ;

def mostColorcode(partlist) {
	my allfarbcodes = call globalColorList(partlist, true,false);		   
	my farbcodes = FilterList(UniqueList(allfarbcodes), 'p', `StrLen(p) eq 0;`);
	my result = List();

	my allfarbcodesstr = ListToString(allfarbcodes, ':');

	my max = 0;
	my maxcolor = '';
	for (my c: farbcodes) {
		my count = StrCountOccurrence(allfarbcodesstr, c);
		if (count gt max) {
			maxcolor = c;
			max = count;
		}
		/*
		my entry = List();
		entry['farbcode'] = c;
		entry['count'] = count;
		ListAdd(result, entry);
		*/
		maxcolor;
	};
};


def kettenElementDefinitions(part,index,mode) { 
      my retval = '';
      my laenge = Feature('f_kettenBreite_top') * 0.1;
      my hoehe = Feature('f_height') * 0.1;
      my breite = Feature('f_kettenGliedBreite_top');
      my x = (_pos + breite)/laenge;
      my alpha = (Power(E,x) - Power(E,-x)); /* Ableitung */
      my func = 'Power(E,x) + Power(E,-x)';
      my delta = breite * Cos(alpha);
      x = (_pos + delta)/laenge;
      alpha = (Power(E,x) - Power(E,-x)); /* Ableitung */
      if (mode eq 'transx') {
         delta = breite * Cos(alpha);  
         _pos = _pos + delta;    
         retval = _pos;
      } else if (mode eq 'transz') {
         retval = Eval(func) * hoehe;
      } else if (mode eq 'roty') {
         retval = - ATan(alpha) * 2 / PI * 90;
      }
      return retval;
   }

def kettenElementAmount(part) { 
   my breite = Feature('f_kettenBreite_top') * 0.1;
   my hoehe = Feature('f_height') * 0.1;
   my posx = 0;
   my posz = 0;
      my diag = Power(breite,2) + Power(hoehe,2);
      diag = Sqrt(diag);
      my amount = Round(diag/3,1.0);
      for (my i: IndexList(amount)) {
         posx = call kettenElementDefinitions(part,i,'transx');
         posz = call kettenElementDefinitions(part,i,'transz');
         if (posx gt breite or posz gt hoehe) {
          break;
        }
      }
      return amount;
   }

def cosh(value) {
			return (Exp(value) + Exp(-value))/2;
		};

def arcosh(value) {
			return  Log( value + Sqrt(Power(value,2) - 1));
		};

def sinh(value) {
			return (Exp(value) - Exp(-value))/2;
		};

def arsinh(value) {
			return  Log(value + Sqrt(Power(value,2) + 1));
		};

