def getVolumeSideSpheres(v, index) {
	my s = GetVolumeRefParts(v);
	my list = List();
	if (index == 0) {
		ListAdd(list, s[0]);
        ListAdd(list, s[1]);
        ListAdd(list, s[5]);
    	ListAdd(list, s[4]);
      } else 
      if (index == 1) {
        ListAdd(list, s[1]);
        ListAdd(list, s[2]);
        ListAdd(list, s[6]);
        ListAdd(list, s[5]);
      } else 
      if (index == 2) {
		ListAdd(list, s[2]);
		ListAdd(list, s[3]);
		ListAdd(list, s[7]);
		ListAdd(list, s[6]);
	 } else 
	 if (index == 3) {
		ListAdd(list, s[3]);
		ListAdd(list, s[0]);
		ListAdd(list, s[4]);
		ListAdd(list, s[7]);
	 } else 
	 if (index == 4) {
		ListAdd(list, s[0]);
		ListAdd(list, s[3]);
		ListAdd(list, s[2]);
	    ListAdd(list, s[1]);
	 } else 
	 if (index == 5) {
		ListAdd(list, s[4]);
		ListAdd(list, s[5]);
		ListAdd(list, s[6]);
		ListAdd(list, s[7]);
	 }
	return list;
}

		def getVolumePlane(v, index) {
      		my points = call getVolumeSideSpheres(v, index);
			my p0 = PartPos(points[0]);
			my p1 = PartPos(points[1]);
			my p2 = PartPos(points[2]);
			my d1 = VectorSub(p1, p0);
			my d2 = VectorSub(p2, p0);
			my planenormal = VectorCrossProduct(d1, d2);
			return List(p0, VectorNormalize(planenormal));
		}

/* o: point in plane, n: planenormal, p: point to test distance */
def pointPlaneDistance(o, n, p) {
	my d = VectorDotProduct(n,p) - VectorDotProduct(n,o);
	return Abs(d);
}

def getVolumePlaneNormalForPipe(pipe) {
	my v = GetRefVolumes(pipe, 'mainstructure');
	v = v[0];
	if (not v) {
		return null;
	};
	for (my index : IndexList(4)) {
		my plane = call getVolumePlane(v, index);
		my normal = plane[1];
		my dist = call pointPlaneDistance(plane[0], normal, PartPos(pipe));
		if (dist lt 1.0) {
			return normal;
		}
	}
	return null;
}

def horizontalPipeVolumeFrontDockTransformation(pipe) {
	my normal = call getVolumePlaneNormalForPipe(pipe);
	my g_center = PartPos(pipe);
	my zUpVector = Vector(0,0,1);
	my g_x = VectorAdd(g_center, normal); /* point in front of volume */
	my g_y = VectorAdd(g_center, VectorCrossProduct(zUpVector, normal));
	my g_z = VectorAdd(g_center, zUpVector);
	my center = LocalPos(pipe, g_center);
	my dir_x = VectorSub(LocalPos(pipe, g_x), center);
	my dir_y = VectorSub(LocalPos(pipe, g_y), center);
	my dir_z = VectorSub(LocalPos(pipe, g_z), center);
	my matrix = call matrixFromCoordinateSystem(dir_x, dir_y, dir_z, center);

	return Matrix2Transformation(matrix);
}
